   699→  private calculateWindowDays(rule: PmType, dailyKm: number): number {
   700→    const intervalKm = rule.intervalKm ?? 180000;
   701→    const tolerancePct = Number(rule.lateTolerancePct ?? 10) / 100;
   702→    return Math.round((intervalKm * tolerancePct) / Math.max(dailyKm, 1));
   703→  }
