  1199→  private calculateMetrics(
  1200→    plan: StrategicAllocation[],
  1201→    // eslint-disable-next-line @typescript-eslint/no-unused-vars
  1202→    _envelopes: ConstraintEnvelope[]
  1203→  ): PlanMetrics {
  1204→    const totalPMs = plan.length;
  1205→    const totalHours = plan.reduce((sum, a) => sum + a.estimatedHours, 0);
  1206→    const totalCost = plan.reduce((sum, a) => sum + a.estimatedCost, 0);
  1207→
  1208→    const quarterLoads = this.groupByQuarter(plan);
  1209→    const loadValues = Object.values(quarterLoads);
  1210→    const averageQuarterlyLoad = loadValues.length > 0
  1211→      ? loadValues.reduce((a, b) => a + b, 0) / loadValues.length
  1212→      : 0;
  1213→    const loadVariance = this.calculateVariance(loadValues);
  1214→
  1215→    // Calculate compliance rate (simplified)
  1216→    const complianceRate = 0.95; // Would need actual constraint checking
  1217→
  1218→    // Calculate bow wave risk
  1219→    const quarters = Object.keys(quarterLoads).sort();
  1220→    let bowWaveRisk = 0;
  1221→    if (quarters.length > 4) {
  1222→      const firstHalf = quarters.slice(0, Math.floor(quarters.length / 2));
  1223→      const secondHalf = quarters.slice(Math.floor(quarters.length / 2));
  1224→
  1225→      const firstHalfLoad = firstHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);
  1226→      const secondHalfLoad = secondHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);
