/**
 * MMS Strategic Planner Service
 *
 * Generates and maintains 1-10 year strategic plans using genetic algorithms,
 * constrained by capacity envelopes from the tactical model.
 *
 * Key responsibilities:
 * - Project PM requirements for all trains over 10-year horizon
 * - Generate quarterly constraint envelopes (track, labor, material)
 * - Run genetic algorithm to optimize PM allocations
 * - Validate plans against capacity constraints
 * - Calculate plan metrics and fitness scores
 *
 * The strategic planner creates long-term maintenance schedules that:
 * - Respect PM hierarchy (C4 satisfies C1/C2/C3)
 * - Handle dual triggers (mileage OR time)
 * - Balance workload across quarters
 * - Avoid bow-wave accumulation
 *
 * @see specs/004-domain-services.md Section 4.5
 */

import { eq, and, desc, lte, isNull } from 'drizzle-orm';
import { addDays, addMonths, addYears, differenceInDays, format } from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  pmTypes,
  pmSchedule,
  trains,
  tracks,
  manhourCapacity,
  type PmType,
} from '../lib/db/schema';
import { getRouteUtilizationService } from './route-utilization';

// =============================================================================
// Types
// =============================================================================

/** Configuration for the genetic algorithm */
export interface StrategicPlannerConfig {
  horizonYears: number;
  granularity: 'MONTHLY' | 'QUARTERLY';
  populationSize: number;
  generations: number;
  mutationRate: number;
  eliteCount: number;
}

/** Default configuration values */
export const DEFAULT_CONFIG: StrategicPlannerConfig = {
  horizonYears: 10,
  granularity: 'QUARTERLY',
  populationSize: 100,
  generations: 500,
  mutationRate: 0.1,
  eliteCount: 10,
};

/** PM requirement projected over the horizon */
export interface PMRequirement {
  id: string;
  trainId: string;
  trainNumber: string;
  fleetId: string;
  pmTypeId: string;
  pmCode: string;
  projectedDate: Date;
  projectedMileageKm: number;
  triggerType: 'MILEAGE' | 'TIME';
  confidence: 'HISTORICAL' | 'ESTIMATED';
  estimatedHours: number;
  trackType: string;
  durationDays: number;
  constraintStart: Date;
  constraintEnd: Date;
}

/** Strategic allocation result (chromosome gene) */
export interface StrategicAllocation {
  requirementId: string;
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  targetQuarter: string; // e.g., '2028-Q2'
  targetDate: Date;
  estimatedHours: number;
  estimatedCost: number;
  depotId: string | null;
}

/** Capacity envelope for a time period */
export interface ConstraintEnvelope {
  period: Date;
  quarterKey: string;
  trackCapacity: Array<{
    trackType: string;
    availableSlotDays: number;
    depotId: string;
  }>;
  laborCapacity: Array<{
    depotId: string;
    availableHours: number;
  }>;
  materialCapacity: Record<string, number>;
  totalAvailableHours: number;
  totalTrackSlots: number;
}

/** Validation result for a strategic plan */
export interface PlanValidation {
  valid: boolean;
  violations: PlanViolation[];
  warnings: PlanWarning[];
  score: number;
}

/** A constraint violation */
export interface PlanViolation {
  type: 'TRACK_CAPACITY' | 'LABOR_CAPACITY' | 'COMPLIANCE_WINDOW' | 'BOW_WAVE';
  quarter: string;
  description: string;
  severity: number;
}

/** A warning (non-blocking) */
export interface PlanWarning {
  type: 'HIGH_UTILIZATION' | 'UNEVEN_DISTRIBUTION' | 'LATE_PM';
  quarter: string;
  description: string;
}

/** Metrics for a strategic plan */
export interface PlanMetrics {
  totalPMs: number;
  totalHours: number;
  totalCost: number;
  averageQuarterlyLoad: number;
  loadVariance: number;
  complianceRate: number;
  bowWaveRisk: number;
  utilizationBalance: number;
}

/** Complete strategic plan result */
export interface StrategicPlanResult {
  planId: string;
  generatedAt: Date;
  horizonStart: Date;
  horizonEnd: Date;
  config: StrategicPlannerConfig;
  plan: StrategicAllocation[];
  validation: PlanValidation;
  metrics: PlanMetrics;
  generationStats: GenerationStats[];
}

/** Statistics for each GA generation */
export interface GenerationStats {
  generation: number;
  bestFitness: number;
  averageFitness: number;
  worstFitness: number;
}

/** PM history entry for projection calculations */
interface PMHistory {
  id: string;
  trainId: string;
  pmTypeId: string;
  pmCode: string;
  completionDate: Date;
  mileageAtCompletion: number;
}

/** Fleet state snapshot */
interface FleetState {
  trains: Array<{
    id: string;
    trainNumber: string;
    fleetId: string;
    currentMileageKm: number;
    commissioningDate: Date;
    fitnessStatus: string | null;
  }>;
}

/** Progress callback for long-running operations */
export type ProgressCallback = (progress: {
  stage: string;
  percent: number;
  generation?: number;
  fitness?: number;
  message?: string;
}) => void;

/** Request to generate a strategic plan */
export interface GeneratePlanRequest {
  horizonYears?: number;
  fleetId?: string;
  fromBaselineId?: string;
  populationSize?: number;
  generations?: number;
  onProgress?: ProgressCallback;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: StrategicPlannerService | null = null;

/**
 * Get the singleton StrategicPlannerService instance
 */
export function getStrategicPlannerService(): StrategicPlannerService {
  if (!instance) {
    instance = new StrategicPlannerService();
  }
  return instance;
}

// =============================================================================
// Service Implementation
// =============================================================================

export class StrategicPlannerService extends BaseService {
  constructor() {
    super({ name: 'StrategicPlannerService' });
  }

  // ===========================================================================
  // Public Methods
  // ===========================================================================

  /**
   * Generate a strategic plan for the specified horizon
   */
  async generatePlan(request: GeneratePlanRequest): Promise<StrategicPlanResult> {
    return this.traced(
      'generatePlan',
      async () => {
        const config: StrategicPlannerConfig = {
          ...DEFAULT_CONFIG,
          horizonYears: request.horizonYears ?? DEFAULT_CONFIG.horizonYears,
          populationSize: request.populationSize ?? DEFAULT_CONFIG.populationSize,
          generations: request.generations ?? DEFAULT_CONFIG.generations,
        };

        const planId = crypto.randomUUID();
        const startTime = new Date();
        const horizonEnd = addYears(startTime, config.horizonYears);
        const generationStats: GenerationStats[] = [];

        // Report progress
        const reportProgress = (stage: string, percent: number, extra?: Record<string, unknown>) => {
          if (request.onProgress) {
            request.onProgress({ stage, percent, ...extra });
          }
        };

        reportProgress('INITIALIZING', 0, { message: 'Loading fleet state...' });

        // 1. Load current fleet state
        const fleetState = await this.getFleetState(request.fleetId);
        this.log.info(
          { trainCount: fleetState.trains.length },
          'Loaded fleet state for strategic planning'
        );

        reportProgress('PROJECTING', 10, { message: 'Projecting PM requirements...' });

        // 2. Project PM requirements for each train
        const pmRequirements = await this.projectPMRequirements(
          fleetState,
          config.horizonYears,
          request.fromBaselineId
        );
        this.log.info(
          { pmCount: pmRequirements.length },
          'Projected PM requirements'
        );

        reportProgress('GENERATING_ENVELOPES', 20, { message: 'Generating constraint envelopes...' });

        // 3. Generate constraint envelopes for each quarter
        const envelopes = await this.generateEnvelopes(startTime, horizonEnd);
        this.log.info(
          { envelopeCount: envelopes.length },
          'Generated constraint envelopes'
        );

        reportProgress('OPTIMIZING', 30, { message: 'Running genetic algorithm...' });

        // 4. Run genetic algorithm
        const bestPlan = await this.runGeneticAlgorithm(
          pmRequirements,
          envelopes,
          config,
          (gen, fitness, avg) => {
            // Report every 50 generations
            if (gen % 50 === 0 || gen === config.generations - 1) {
              const percent = 30 + Math.round((gen / config.generations) * 60);
              reportProgress('OPTIMIZING', percent, {
                generation: gen,
                fitness,
                message: `Generation ${gen}/${config.generations}, Fitness: ${fitness.toFixed(2)}`,
              });
            }
            generationStats.push({
              generation: gen,
              bestFitness: fitness,
              averageFitness: avg,
              worstFitness: 0, // Calculated in GA
            });
          }
        );

        reportProgress('VALIDATING', 95, { message: 'Validating plan...' });

        // 5. Validate against constraint envelopes
        let validation = this.validatePlan(bestPlan, envelopes);

        // 6. Attempt repair if invalid
        let finalPlan = bestPlan;
        if (!validation.valid) {
          this.log.warn(
            { violations: validation.violations.length },
            'Plan has violations, attempting repair'
          );
          finalPlan = this.repairPlan(bestPlan, validation, envelopes);
          validation = this.validatePlan(finalPlan, envelopes);
        }

        // 7. Calculate metrics
        const metrics = this.calculateMetrics(finalPlan, envelopes);

        reportProgress('COMPLETE', 100, { message: 'Strategic plan generated' });

        return {
          planId,
          generatedAt: startTime,
          horizonStart: startTime,
          horizonEnd,
          config,
          plan: finalPlan,
          validation,
          metrics,
          generationStats,
        };
      },
      { 'planner.horizonYears': request.horizonYears ?? DEFAULT_CONFIG.horizonYears }
    );
  }

  /**
   * Get capacity envelope for a specific quarter
   */
  async getQuarterEnvelope(
    quarterStart: Date,
    quarterEnd: Date,
    depotIds?: string[]
  ): Promise<ConstraintEnvelope> {
    return this.generateEnvelopeForPeriod(quarterStart, quarterEnd, depotIds);
  }

  /**
   * Project PM requirements for specific trains
   */
  async projectTrainPMs(
    trainIds: string[],
    horizonYears: number = 10
  ): Promise<PMRequirement[]> {
    const requirements: PMRequirement[] = [];

    for (const trainId of trainIds) {
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) continue;

      // Convert to FleetState train format
      const trainState = {
        id: train.id,
        trainNumber: train.trainNumber,
        fleetId: train.fleetId,
        currentMileageKm: train.currentMileageKm ?? 0,
        commissioningDate: train.commissioningDate
          ? new Date(train.commissioningDate)
          : new Date(),
        fitnessStatus: train.fitnessStatus,
      };

      const trainRules = await this.getPMRulesForFleet(train.fleetId);
      const trainHistory = await this.getPMHistoryForTrain(trainId);
      const dailyKm = await this.calculateDailyUtilization(trainState, trainHistory);

      const trainProjections = await this.projectTrainPMsInternal(
        trainState,
        trainRules,
        trainHistory,
        addYears(new Date(), horizonYears),
        dailyKm
      );

      requirements.push(...trainProjections);
    }

    return requirements;
  }

  // ===========================================================================
  // Private Methods - Fleet State
  // ===========================================================================

  private async getFleetState(fleetId?: string): Promise<FleetState> {
    const trainData = await this.db.query.trains.findMany({
      where: fleetId ? eq(trains.fleetId, fleetId) : undefined,
    });

    return {
      trains: trainData
        .filter((t) => t.fitnessStatus !== 'GROUNDED')
        .map((t) => ({
          id: t.id,
          trainNumber: t.trainNumber,
          fleetId: t.fleetId,
          currentMileageKm: t.currentMileageKm ?? 0,
          commissioningDate: t.commissioningDate
            ? new Date(t.commissioningDate)
            : new Date(),
          fitnessStatus: t.fitnessStatus,
        })),
    };
  }

  // ===========================================================================
  // Private Methods - PM Projection
  // ===========================================================================

  /**
   * Project PM requirements for all trains over the planning horizon
   */
  private async projectPMRequirements(
    fleetState: FleetState,
    horizonYears: number,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    _fromBaselineId?: string
  ): Promise<PMRequirement[]> {
    const requirements: PMRequirement[] = [];
    const horizonEnd = addYears(new Date(), horizonYears);

    for (const train of fleetState.trains) {
      const trainRules = await this.getPMRulesForFleet(train.fleetId);
      const trainHistory = await this.getPMHistoryForTrain(train.id);
      const dailyKm = await this.calculateDailyUtilization(train, trainHistory);

      const trainProjections = await this.projectTrainPMsInternal(
        train,
        trainRules,
        trainHistory,
        horizonEnd,
        dailyKm
      );

      requirements.push(...trainProjections);
    }

    return requirements;
  }

  /**
   * Project all PM events for a single train over the horizon
   */
  private async projectTrainPMsInternal(
    train: FleetState['trains'][0],
    pmRules: PmType[],
    pmHistory: PMHistory[],
    horizonEnd: Date,
    dailyKm: number
  ): Promise<PMRequirement[]> {
    const projections: PMRequirement[] = [];
    const workingHistory = [...pmHistory];
    let currentMileage = train.currentMileageKm;
    let currentDate = new Date();

    // Project until we exceed horizon
    while (currentDate < horizonEnd) {
      // Find next PM due across all PM types
      let nextPM: {
        rule: PmType;
        date: Date;
        mileage: number;
        trigger: 'MILEAGE' | 'TIME';
      } | null = null;

      for (const rule of pmRules) {
        if (!rule.active) continue;

        const projection = this.calculateNextPMDue(
          train,
          rule,
          pmRules,
          workingHistory,
          currentMileage,
          currentDate,
          dailyKm
        );

        if (!nextPM || projection.date < nextPM.date) {
          nextPM = {
            rule,
            date: projection.date,
            mileage: projection.mileage,
            trigger: projection.trigger,
          };
        }
      }

      if (!nextPM || nextPM.date > horizonEnd) break;

      // Calculate compliance window
      const windowDays = this.calculateWindowDays(nextPM.rule, dailyKm);

      // Create requirement
      const requirement: PMRequirement = {
        id: crypto.randomUUID(),
        trainId: train.id,
        trainNumber: train.trainNumber,
        fleetId: train.fleetId,
        pmTypeId: nextPM.rule.id,
        pmCode: nextPM.rule.pmCode,
        projectedDate: nextPM.date,
        projectedMileageKm: nextPM.mileage,
        triggerType: nextPM.trigger,
        confidence: workingHistory.length > 0 ? 'HISTORICAL' : 'ESTIMATED',
        estimatedHours: Number(nextPM.rule.estimatedHours) || 8,
        trackType: nextPM.rule.trackType,
        durationDays: nextPM.rule.minTrackDays ?? 1,
        constraintStart: addDays(nextPM.date, -windowDays),
        constraintEnd: addDays(nextPM.date, windowDays),
      };

      projections.push(requirement);

      // Add to working history for cascading projection
      workingHistory.push({
        id: requirement.id,
        trainId: train.id,
        pmTypeId: nextPM.rule.id,
        pmCode: nextPM.rule.pmCode,
        completionDate: nextPM.date,
        mileageAtCompletion: nextPM.mileage,
      });

      // Advance state past this PM
      const trackDays = nextPM.rule.minTrackDays ?? 1;
      currentDate = addDays(nextPM.date, trackDays);
      currentMileage = nextPM.mileage + trackDays * dailyKm * 0.1; // Small mileage during PM
    }

    return projections;
  }

  /**
   * Calculate when the next instance of a specific PM type is due
   *
   * Handles PM hierarchy (C4 satisfies C1/C2/C3) and cold start cases
   */
  private calculateNextPMDue(
    train: FleetState['trains'][0],
    targetRule: PmType,
    allRules: PmType[],
    history: PMHistory[],
    currentMileage: number,
    currentDate: Date,
    dailyKm: number
  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {
    // 1. Find all PM types that SATISFY the target PM
    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);

    // 2. Find the most recent PM that satisfies this requirement
    const lastSatisfying = history
      .filter((h) => satisfyingCodes.includes(h.pmCode))
      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];

    // 3. Handle "Cold Start" - no PM history exists
    let lastMileage: number;
    let lastDate: Date;

    if (lastSatisfying) {
      lastMileage = lastSatisfying.mileageAtCompletion;
      lastDate = lastSatisfying.completionDate;
    } else {
      // COLD START FIX: Create "virtual" last PM
      const intervalKm = targetRule.intervalKm ?? 180000;
      const cyclesCompleted = Math.floor(currentMileage / intervalKm);

      if (cyclesCompleted > 0) {
        lastMileage = cyclesCompleted * intervalKm;
        const daysAgo = (currentMileage - lastMileage) / Math.max(dailyKm, 1);
        lastDate = addDays(currentDate, -Math.round(daysAgo));
      } else {
        lastMileage = 0;
        lastDate = train.commissioningDate;
      }
    }

    // 4. Calculate mileage-based due date
    const intervalKm = targetRule.intervalKm ?? 180000;
    const kmSinceLast = currentMileage - lastMileage;
    const kmRemaining = Math.max(0, intervalKm - kmSinceLast);
    const daysUntilMileageDue = dailyKm > 0 ? kmRemaining / dailyKm : 365;
    const dateByMileage = addDays(currentDate, Math.round(daysUntilMileageDue));
    const mileageAtDue = currentMileage + kmRemaining;

    // 5. Calculate time-based due date (if interval defined)
    let dateByTime: Date | null = null;
    if (targetRule.intervalMonths) {
      dateByTime = addMonths(lastDate, targetRule.intervalMonths);
    }

    // 6. Return whichever comes first (dual trigger)
    if (dateByTime && dateByTime < dateByMileage) {
      const daysUntilTime = Math.max(0, differenceInDays(dateByTime, currentDate));
      const mileageAtTime = currentMileage + daysUntilTime * dailyKm;
      return { date: dateByTime, mileage: mileageAtTime, trigger: 'TIME' };
    } else {
      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
    }
  }

  /**
   * Find all PM codes that satisfy a target PM code
   */
  private getSatisfyingCodes(targetCode: string, allRules: PmType[]): string[] {
    const result = [targetCode];

    for (const rule of allRules) {
      if (rule.satisfiesCodes?.includes(targetCode)) {
        result.push(rule.pmCode);
      }
    }

    return result;
  }

  /**
   * Calculate daily mileage rate for a train
   */
  private async calculateDailyUtilization(
    train: FleetState['trains'][0],
    history: PMHistory[]
  ): Promise<number> {
    // Try to get from route utilization service
    try {
      const routeService = getRouteUtilizationService();
      const targetDate = format(new Date(), 'yyyy-MM-dd');
      const rate = await routeService.calculateDailyRate(train.id, targetDate);
      if (rate.dailyKm > 50 && rate.dailyKm < 500) {
        return rate.dailyKm;
      }
    } catch {
      // Fall through to calculation
    }

    // Filter valid history entries
    const validHistory = history
      .filter((h) => h.mileageAtCompletion > 0)
      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime());

    // Try: Recent velocity between last 2 PMs
    if (validHistory.length >= 2) {
      const recent = validHistory[0];
      const previous = validHistory[1];
      const daysBetween = differenceInDays(recent.completionDate, previous.completionDate);
      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;

      if (daysBetween >= 14 && kmBetween > 0) {
        const rate = kmBetween / daysBetween;
        if (rate > 50 && rate < 500) {
          return rate;
        }
      }
    }

    // Fallback: Lifetime average from commissioning
    const daysSinceCommission = differenceInDays(new Date(), train.commissioningDate);
    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
      return train.currentMileageKm / daysSinceCommission;
    }

    // Last resort: Fleet typical value
    return 150; // Conservative metro average
  }

  private calculateWindowDays(rule: PmType, dailyKm: number): number {
    const intervalKm = rule.intervalKm ?? 180000;
    const tolerancePct = Number(rule.lateTolerancePct ?? 10) / 100;
    return Math.round((intervalKm * tolerancePct) / Math.max(dailyKm, 1));
  }

  private async getPMRulesForFleet(fleetId: string): Promise<PmType[]> {
    const today = format(new Date(), 'yyyy-MM-dd');

    return this.db.query.pmTypes.findMany({
      where: and(
        eq(pmTypes.fleetId, fleetId),
        eq(pmTypes.active, true),
        lte(pmTypes.effectiveFrom, today),
        isNull(pmTypes.effectiveTo)
      ),
    });
  }

  private async getPMHistoryForTrain(trainId: string): Promise<PMHistory[]> {
    const completed = await this.db.query.pmSchedule.findMany({
      where: and(
        eq(pmSchedule.trainId, trainId),
        eq(pmSchedule.status, 'COMPLETED'),
        isNull(pmSchedule.scenarioId)
      ),
      orderBy: desc(pmSchedule.completedAt),
    });

    const pmTypeMap = new Map<string, string>();
    for (const pm of completed) {
      if (!pmTypeMap.has(pm.pmTypeId)) {
        const pmType = await this.db.query.pmTypes.findFirst({
          where: eq(pmTypes.id, pm.pmTypeId),
        });
        if (pmType) pmTypeMap.set(pm.pmTypeId, pmType.pmCode);
      }
    }

    return completed.map((pm) => ({
      id: pm.id,
      trainId: pm.trainId,
      pmTypeId: pm.pmTypeId,
      pmCode: pmTypeMap.get(pm.pmTypeId) ?? 'UNKNOWN',
      completionDate: pm.completedAt ?? new Date(),
      mileageAtCompletion: pm.completedMileageKm ?? 0,
    }));
  }

  // ===========================================================================
  // Private Methods - Constraint Envelopes
  // ===========================================================================

  private async generateEnvelopes(
    startDate: Date,
    endDate: Date
  ): Promise<ConstraintEnvelope[]> {
    const envelopes: ConstraintEnvelope[] = [];
    const depotIds = await this.getAllDepotIds();

    // Generate envelope for each quarter
    for (let q = 0; q < differenceInDays(endDate, startDate) / 90; q++) {
      const quarterStart = addMonths(startDate, q * 3);
      const quarterEnd = addMonths(quarterStart, 3);

      if (quarterStart > endDate) break;

      const envelope = await this.generateEnvelopeForPeriod(
        quarterStart,
        quarterEnd,
        depotIds
      );

      envelopes.push(envelope);
    }

    return envelopes;
  }

  private async generateEnvelopeForPeriod(
    periodStart: Date,
    periodEnd: Date,
    depotIds?: string[]
  ): Promise<ConstraintEnvelope> {
    const quarterKey = this.getQuarterKey(periodStart);
    const daysInPeriod = differenceInDays(periodEnd, periodStart);

    // Get all depots if not specified
    const depots = depotIds
      ? depotIds
      : await this.getAllDepotIds();

    // Track capacity by depot and type
    const trackCapacity: ConstraintEnvelope['trackCapacity'] = [];
    for (const depotId of depots) {
      const trackData = await this.db.query.tracks.findMany({
        where: eq(tracks.depotId, depotId),
      });

      const tracksByType = new Map<string, number>();
      for (const track of trackData) {
        const current = tracksByType.get(track.trackType) ?? 0;
        tracksByType.set(track.trackType, current + 1);
      }

      for (const [trackType, count] of tracksByType) {
        trackCapacity.push({
          trackType,
          availableSlotDays: count * daysInPeriod * 0.85, // 85% utilization target
          depotId,
        });
      }
    }

    // Labor capacity by depot
    const laborCapacity: ConstraintEnvelope['laborCapacity'] = [];
    for (const depotId of depots) {
      const capacity = await this.db.query.manhourCapacity.findFirst({
        where: eq(manhourCapacity.depotId, depotId),
      });

      if (capacity) {
        const dailyHours =
          Number(capacity.dayShiftHours ?? 0) +
          Number(capacity.nightShiftHours ?? 0);
        laborCapacity.push({
          depotId,
          availableHours: dailyHours * daysInPeriod,
        });
      }
    }

    const totalAvailableHours = laborCapacity.reduce((sum, l) => sum + l.availableHours, 0);
    const totalTrackSlots = trackCapacity.reduce((sum, t) => sum + t.availableSlotDays, 0);

    return {
      period: periodStart,
      quarterKey,
      trackCapacity,
      laborCapacity,
      materialCapacity: {}, // Simplified - would need inventory integration
      totalAvailableHours,
      totalTrackSlots,
    };
  }

  private async getAllDepotIds(): Promise<string[]> {
    const depotData = await this.db.query.depots.findMany();
    return depotData.map((d) => d.id);
  }

  private getQuarterKey(date: Date): string {
    const year = date.getFullYear();
    const quarter = Math.floor(date.getMonth() / 3) + 1;
    return `${year}-Q${quarter}`;
  }

  // ===========================================================================
  // Private Methods - Genetic Algorithm
  // ===========================================================================

  private async runGeneticAlgorithm(
    requirements: PMRequirement[],
    envelopes: ConstraintEnvelope[],
    config: StrategicPlannerConfig,
    onGeneration?: (gen: number, bestFitness: number, avgFitness: number) => void
  ): Promise<StrategicAllocation[]> {
    // Initialize population
    let population = this.initializePopulation(requirements, envelopes, config.populationSize);

    for (let gen = 0; gen < config.generations; gen++) {
      // Evaluate fitness
      const fitness = population.map((individual) =>
        this.evaluateFitness(individual, envelopes)
      );

      const bestFitness = Math.max(...fitness);
      const avgFitness = fitness.reduce((a, b) => a + b, 0) / fitness.length;

      if (onGeneration) {
        onGeneration(gen, bestFitness, avgFitness);
      }

      // Selection
      const selected = this.tournamentSelection(population, fitness, config.populationSize);

      // Crossover
      const offspring = this.crossover(selected, config.populationSize - config.eliteCount);

      // Mutation
      const mutated = this.mutate(offspring, envelopes, config.mutationRate);

      // Elitism - keep best individuals
      const elite = this.selectElite(population, fitness, config.eliteCount);

      // New population
      population = [...elite, ...mutated];
    }

    // Return best individual
    const finalFitness = population.map((i) => this.evaluateFitness(i, envelopes));
    const bestIndex = finalFitness.indexOf(Math.max(...finalFitness));

    return population[bestIndex];
  }

  private initializePopulation(
    requirements: PMRequirement[],
    envelopes: ConstraintEnvelope[],
    populationSize: number
  ): StrategicAllocation[][] {
    const population: StrategicAllocation[][] = [];

    for (let i = 0; i < populationSize; i++) {
      const individual: StrategicAllocation[] = requirements.map((req) => {
        // Find valid quarters for this requirement
        const validQuarters = envelopes.filter(
          (e) => e.period >= req.constraintStart && e.period <= req.constraintEnd
        );

        // Randomly select a quarter (or closest if none in window)
        let targetEnvelope: ConstraintEnvelope;
        if (validQuarters.length > 0) {
          targetEnvelope = validQuarters[Math.floor(Math.random() * validQuarters.length)];
        } else {
          // Find closest envelope to constraint window
          targetEnvelope = envelopes.reduce((closest, env) => {
            const distCurrent = Math.abs(env.period.getTime() - req.projectedDate.getTime());
            const distClosest = Math.abs(closest.period.getTime() - req.projectedDate.getTime());
            return distCurrent < distClosest ? env : closest;
          });
        }

        return {
          requirementId: req.id,
          trainId: req.trainId,
          trainNumber: req.trainNumber,
          pmTypeId: req.pmTypeId,
          pmCode: req.pmCode,
          targetQuarter: targetEnvelope.quarterKey,
          targetDate: req.projectedDate,
          estimatedHours: req.estimatedHours,
          estimatedCost: req.estimatedHours * 75, // Rough cost estimate
          depotId: null,
        };
      });

      population.push(individual);
    }

    return population;
  }

  private evaluateFitness(
    individual: StrategicAllocation[],
    envelopes: ConstraintEnvelope[]
  ): number {
    let fitness = 1000; // Start with base score

    // Penalty for constraint envelope violations
    for (const envelope of envelopes) {
      const quarterAllocations = individual.filter(
        (a) => a.targetQuarter === envelope.quarterKey
      );

      // Labor capacity check
      const totalHours = quarterAllocations.reduce((sum, a) => sum + a.estimatedHours, 0);
      if (totalHours > envelope.totalAvailableHours) {
        fitness -= (totalHours - envelope.totalAvailableHours) * 5;
      }

      // Track capacity check (simplified)
      if (quarterAllocations.length > envelope.totalTrackSlots) {
        fitness -= (quarterAllocations.length - envelope.totalTrackSlots) * 10;
      }
    }

    // Bonus for workload leveling
    const quarterHours = this.groupByQuarter(individual);
    const variance = this.calculateVariance(Object.values(quarterHours));
    fitness -= variance * 0.1; // Prefer even distribution

    return Math.max(0, fitness);
  }

  private tournamentSelection(
    population: StrategicAllocation[][],
    fitness: number[],
    targetSize: number
  ): StrategicAllocation[][] {
    const selected: StrategicAllocation[][] = [];
    const tournamentSize = 3;

    while (selected.length < targetSize) {
      // Pick random tournament participants
      const participants: number[] = [];
      while (participants.length < tournamentSize) {
        const idx = Math.floor(Math.random() * population.length);
        if (!participants.includes(idx)) {
          participants.push(idx);
        }
      }

      // Select winner (highest fitness)
      const winnerIdx = participants.reduce((best, current) =>
        fitness[current] > fitness[best] ? current : best
      );

      selected.push([...population[winnerIdx]]);
    }

    return selected;
  }

  private crossover(
    selected: StrategicAllocation[][],
    offspringCount: number
  ): StrategicAllocation[][] {
    const offspring: StrategicAllocation[][] = [];

    while (offspring.length < offspringCount) {
      const parent1 = selected[Math.floor(Math.random() * selected.length)];
      const parent2 = selected[Math.floor(Math.random() * selected.length)];

      // Single-point crossover
      const crossPoint = Math.floor(Math.random() * parent1.length);

      const child = [
        ...parent1.slice(0, crossPoint),
        ...parent2.slice(crossPoint),
      ];

      offspring.push(child);
    }

    return offspring;
  }

  private mutate(
    offspring: StrategicAllocation[][],
    envelopes: ConstraintEnvelope[],
    mutationRate: number
  ): StrategicAllocation[][] {
    return offspring.map((individual) =>
      individual.map((allocation) => {
        if (Math.random() < mutationRate) {
          // Mutate: move to a different quarter
          const randomEnvelope = envelopes[Math.floor(Math.random() * envelopes.length)];
          return {
            ...allocation,
            targetQuarter: randomEnvelope.quarterKey,
          };
        }
        return allocation;
      })
    );
  }

  private selectElite(
    population: StrategicAllocation[][],
    fitness: number[],
    eliteCount: number
  ): StrategicAllocation[][] {
    const indexed = population.map((ind, i) => ({ ind, fit: fitness[i] }));
    indexed.sort((a, b) => b.fit - a.fit);
    return indexed.slice(0, eliteCount).map((x) => [...x.ind]);
  }

  private groupByQuarter(individual: StrategicAllocation[]): Record<string, number> {
    const result: Record<string, number> = {};
    for (const alloc of individual) {
      result[alloc.targetQuarter] = (result[alloc.targetQuarter] ?? 0) + alloc.estimatedHours;
    }
    return result;
  }

  private calculateVariance(values: number[]): number {
    if (values.length === 0) return 0;
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const squaredDiffs = values.map((v) => Math.pow(v - mean, 2));
    return squaredDiffs.reduce((a, b) => a + b, 0) / values.length;
  }

  // ===========================================================================
  // Private Methods - Validation & Metrics
  // ===========================================================================

  private validatePlan(
    plan: StrategicAllocation[],
    envelopes: ConstraintEnvelope[]
  ): PlanValidation {
    const violations: PlanViolation[] = [];
    const warnings: PlanWarning[] = [];

    for (const envelope of envelopes) {
      const quarterAllocations = plan.filter(
        (a) => a.targetQuarter === envelope.quarterKey
      );

      // Check labor capacity
      const totalHours = quarterAllocations.reduce((sum, a) => sum + a.estimatedHours, 0);
      if (totalHours > envelope.totalAvailableHours) {
        violations.push({
          type: 'LABOR_CAPACITY',
          quarter: envelope.quarterKey,
          description: `Labor hours (${totalHours.toFixed(0)}) exceed capacity (${envelope.totalAvailableHours.toFixed(0)})`,
          severity: (totalHours - envelope.totalAvailableHours) / envelope.totalAvailableHours,
        });
      } else if (totalHours > envelope.totalAvailableHours * 0.95) {
        warnings.push({
          type: 'HIGH_UTILIZATION',
          quarter: envelope.quarterKey,
          description: `High utilization (${((totalHours / envelope.totalAvailableHours) * 100).toFixed(1)}%)`,
        });
      }

      // Check track capacity
      if (quarterAllocations.length > envelope.totalTrackSlots) {
        violations.push({
          type: 'TRACK_CAPACITY',
          quarter: envelope.quarterKey,
          description: `PMs (${quarterAllocations.length}) exceed track slots (${envelope.totalTrackSlots.toFixed(0)})`,
          severity: (quarterAllocations.length - envelope.totalTrackSlots) / envelope.totalTrackSlots,
        });
      }
    }

    // Check for bow wave (accumulation in later quarters)
    const quarterLoads = this.groupByQuarter(plan);
    const quarters = Object.keys(quarterLoads).sort();
    if (quarters.length > 4) {
      const firstHalf = quarters.slice(0, Math.floor(quarters.length / 2));
      const secondHalf = quarters.slice(Math.floor(quarters.length / 2));

      const firstHalfLoad = firstHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);
      const secondHalfLoad = secondHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);

      if (secondHalfLoad > firstHalfLoad * 1.5) {
        violations.push({
          type: 'BOW_WAVE',
          quarter: 'OVERALL',
          description: 'Maintenance accumulating in later periods (bow wave risk)',
          severity: secondHalfLoad / firstHalfLoad - 1,
        });
      }
    }

    const score = 100 - violations.reduce((sum, v) => sum + v.severity * 20, 0);

    return {
      valid: violations.length === 0,
      violations,
      warnings,
      score: Math.max(0, score),
    };
  }

  private repairPlan(
    plan: StrategicAllocation[],
    validation: PlanValidation,
    envelopes: ConstraintEnvelope[]
  ): StrategicAllocation[] {
    const repairedPlan = [...plan];

    // Try to move allocations from overloaded quarters
    for (const violation of validation.violations) {
      if (violation.type === 'LABOR_CAPACITY' || violation.type === 'TRACK_CAPACITY') {
        const overloadedQuarter = violation.quarter;
        const overloadedAllocations = repairedPlan.filter(
          (a) => a.targetQuarter === overloadedQuarter
        );

        // Find underutilized quarters
        const quarterLoads = this.groupByQuarter(repairedPlan);
        const underutilized = envelopes
          .filter((e) => {
            const load = quarterLoads[e.quarterKey] ?? 0;
            return load < e.totalAvailableHours * 0.7;
          })
          .map((e) => e.quarterKey);

        // Move some allocations
        let movedCount = 0;
        const targetMoves = Math.ceil(overloadedAllocations.length * 0.2);

        for (let i = 0; i < repairedPlan.length && movedCount < targetMoves; i++) {
          if (repairedPlan[i].targetQuarter === overloadedQuarter && underutilized.length > 0) {
            repairedPlan[i] = {
              ...repairedPlan[i],
              targetQuarter: underutilized[Math.floor(Math.random() * underutilized.length)],
            };
            movedCount++;
          }
        }
      }
    }

    return repairedPlan;
  }

  private calculateMetrics(
    plan: StrategicAllocation[],
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    _envelopes: ConstraintEnvelope[]
  ): PlanMetrics {
    const totalPMs = plan.length;
    const totalHours = plan.reduce((sum, a) => sum + a.estimatedHours, 0);
    const totalCost = plan.reduce((sum, a) => sum + a.estimatedCost, 0);

    const quarterLoads = this.groupByQuarter(plan);
    const loadValues = Object.values(quarterLoads);
    const averageQuarterlyLoad = loadValues.length > 0
      ? loadValues.reduce((a, b) => a + b, 0) / loadValues.length
      : 0;
    const loadVariance = this.calculateVariance(loadValues);

    // Calculate compliance rate (simplified)
    const complianceRate = 0.95; // Would need actual constraint checking

    // Calculate bow wave risk
    const quarters = Object.keys(quarterLoads).sort();
    let bowWaveRisk = 0;
    if (quarters.length > 4) {
      const firstHalf = quarters.slice(0, Math.floor(quarters.length / 2));
      const secondHalf = quarters.slice(Math.floor(quarters.length / 2));

      const firstHalfLoad = firstHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);
      const secondHalfLoad = secondHalf.reduce((sum, q) => sum + (quarterLoads[q] ?? 0), 0);

      if (secondHalfLoad > firstHalfLoad) {
        bowWaveRisk = Math.min(1, (secondHalfLoad / firstHalfLoad - 1) / 0.5);
      }
    }

    // Calculate utilization balance (1 = perfectly balanced)
    const utilizationBalance = 1 - Math.min(1, Math.sqrt(loadVariance) / averageQuarterlyLoad);

    return {
      totalPMs,
      totalHours,
      totalCost,
      averageQuarterlyLoad,
      loadVariance,
      complianceRate,
      bowWaveRisk,
      utilizationBalance: isNaN(utilizationBalance) ? 0.5 : utilizationBalance,
    };
  }
}

