   171→  baselineShadowLoading: false,
   172→  baselineShadowError: null,
   173→  baselineShadowLastFetch: null,
   174→  baselineShadowBaselineId: null,
   175→  baselineShadowStatusFilter: null,
   176→
   177→  // Panel state
   178→  manhourPanelExpanded: true,
   179→  driftPanelExpanded: true,
   180→  baselineShadowPanelExpanded: true,
   181→};
   182→
   183→export const overlaySlice = createSlice({
   184→  id: 'overlay',
   185→  initial: initialOverlayState,
   186→  cache: { policy: 'session' },
   187→  reducers: {
   188→    // ==========================================================================
   189→    // Man-hour Overlay Reducers
   190→    // ==========================================================================
   191→
   192→    setManhourLoading: (s, loading: boolean) => {
   193→      const state = s as OverlaySliceState;
   194→      state.manhourLoading = loading;
   195→    },
   196→
   197→    setManhourData: (s, data: ManhourOverlayData) => {
   198→      const state = s as OverlaySliceState;
   199→      state.manhourData = data;
   200→      state.manhourLoading = false;
   201→      state.manhourError = null;
   202→      state.manhourLastFetch = Date.now();
   203→    },
   204→
   205→    setManhourError: (s, error: string) => {
   206→      const state = s as OverlaySliceState;
   207→      state.manhourError = error;
   208→      state.manhourLoading = false;
   209→    },
   210→
   211→    clearManhourData: (s) => {
   212→      const state = s as OverlaySliceState;
   213→      state.manhourData = null;
   214→      state.manhourError = null;
   215→      state.manhourLastFetch = null;
   216→    },
   217→
   218→    setManhourWeeks: (s, weeks: number) => {
   219→      const state = s as OverlaySliceState;
   220→      state.manhourWeeks = weeks;
   221→    },
   222→
   223→    setManhourDepotFilter: (s, depotId: string | null) => {
   224→      const state = s as OverlaySliceState;
   225→      state.manhourDepotFilter = depotId;
   226→    },
   227→
   228→    expandManhourWeek: (s, weekStart: string) => {
   229→      const state = s as OverlaySliceState;
   230→      if (!state.manhourExpandedWeeks.includes(weekStart)) {
   231→        state.manhourExpandedWeeks.push(weekStart);
   232→      }
   233→    },
   234→
   235→    collapseManhourWeek: (s, weekStart: string) => {
   236→      const state = s as OverlaySliceState;
   237→      state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
   238→    },
   239→
   240→    toggleManhourWeek: (s, weekStart: string) => {
   241→      const state = s as OverlaySliceState;
   242→      if (state.manhourExpandedWeeks.includes(weekStart)) {
   243→        state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
   244→      } else {
   245→        state.manhourExpandedWeeks.push(weekStart);
   246→      }
   247→    },
   248→
   249→    toggleManhourPanel: (s) => {
   250→      const state = s as OverlaySliceState;
   251→      state.manhourPanelExpanded = !state.manhourPanelExpanded;
   252→    },
   253→
   254→    // ==========================================================================
   255→    // Drift Overlay Reducers
   256→    // ==========================================================================
   257→
   258→    setDriftLoading: (s, loading: boolean) => {
   259→      const state = s as OverlaySliceState;
   260→      state.driftLoading = loading;
   261→    },
   262→
   263→    setDriftData: (s, data: DriftOverlayData) => {
   264→      const state = s as OverlaySliceState;
   265→      state.driftData = data;
   266→      state.driftLoading = false;
   267→      state.driftError = null;
   268→      state.driftLastFetch = Date.now();
   269→
   270→      // Generate recommendations based on drift data
   271→      state.driftRecommendations = data.trains
   272→        .filter(t => t.driftSeverity !== 'GREEN')
   273→        .map(train => ({
   274→          trainId: train.trainId,
   275→          trainNumber: train.trainNumber,
   276→          recommendation: train.driftSeverity === 'RED' ? 'REPLAN' as const : 'MONITOR' as const,
   277→          reason: train.driftSeverity === 'RED'
   278→            ? `Mileage drift of ${Math.abs(train.mileageDriftPct).toFixed(1)}% exceeds threshold`
   279→            : `Mileage drift approaching threshold at ${Math.abs(train.mileageDriftPct).toFixed(1)}%`,
   280→          priority: train.driftSeverity === 'RED' ? 'HIGH' as const : 'MEDIUM' as const,
   281→        }));
   282→    },
   283→
   284→    setDriftError: (s, error: string) => {
   285→      const state = s as OverlaySliceState;
   286→      state.driftError = error;
   287→      state.driftLoading = false;
   288→    },
   289→
   290→    clearDriftData: (s) => {
   291→      const state = s as OverlaySliceState;
   292→      state.driftData = null;
   293→      state.driftError = null;
   294→      state.driftLastFetch = null;
   295→      state.driftRecommendations = [];
   296→    },
   297→
   298→    setDriftBaselineId: (s, baselineId: string | null) => {
   299→      const state = s as OverlaySliceState;
   300→      state.driftBaselineId = baselineId;
   301→    },
   302→
   303→    setDriftSeverityFilter: (s, severity: DriftSeverity | null) => {
   304→      const state = s as OverlaySliceState;
   305→      state.driftSeverityFilter = severity;
   306→    },
   307→
   308→    expandDriftTrain: (s, trainId: string) => {
   309→      const state = s as OverlaySliceState;
   310→      if (!state.driftExpandedTrains.includes(trainId)) {
   311→        state.driftExpandedTrains.push(trainId);
   312→      }
   313→    },
   314→
   315→    collapseDriftTrain: (s, trainId: string) => {
   316→      const state = s as OverlaySliceState;
   317→      state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
   318→    },
   319→
   320→    toggleDriftTrain: (s, trainId: string) => {
   321→      const state = s as OverlaySliceState;
   322→      if (state.driftExpandedTrains.includes(trainId)) {
   323→        state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
   324→      } else {
   325→        state.driftExpandedTrains.push(trainId);
   326→      }
   327→    },
   328→
   329→    toggleDriftPanel: (s) => {
   330→      const state = s as OverlaySliceState;
   331→      state.driftPanelExpanded = !state.driftPanelExpanded;
   332→    },
   333→
   334→    // ==========================================================================
   335→    // Baseline Shadow Overlay Reducers
   336→    // ==========================================================================
   337→
   338→    setBaselineShadowLoading: (s, loading: boolean) => {
   339→      const state = s as OverlaySliceState;
   340→      state.baselineShadowLoading = loading;
   341→    },
   342→
   343→    setBaselineShadowData: (s, data: BaselineShadowData) => {
   344→      const state = s as OverlaySliceState;
   345→      state.baselineShadowData = data;
   346→      state.baselineShadowLoading = false;
   347→      state.baselineShadowError = null;
   348→      state.baselineShadowLastFetch = Date.now();
   349→    },
   350→
   351→    setBaselineShadowError: (s, error: string) => {
   352→      const state = s as OverlaySliceState;
   353→      state.baselineShadowError = error;
   354→      state.baselineShadowLoading = false;
   355→    },
   356→
   357→    clearBaselineShadowData: (s) => {
   358→      const state = s as OverlaySliceState;
   359→      state.baselineShadowData = null;
   360→      state.baselineShadowError = null;
   361→      state.baselineShadowLastFetch = null;
   362→    },
   363→
   364→    setBaselineShadowBaselineId: (s, baselineId: string | null) => {
   365→      const state = s as OverlaySliceState;
   366→      state.baselineShadowBaselineId = baselineId;
   367→    },
   368→
   369→    setBaselineShadowStatusFilter: (s, status: BaselinePmStatus | null) => {
   370→      const state = s as OverlaySliceState;
   371→      state.baselineShadowStatusFilter = status;
   372→    },
   373→
   374→    toggleBaselineShadowPanel: (s) => {
   375→      const state = s as OverlaySliceState;
   376→      state.baselineShadowPanelExpanded = !state.baselineShadowPanelExpanded;
   377→    },
   378→
   379→    // ==========================================================================
   380→    // General Reducers
   381→    // ==========================================================================
   382→
   383→    reset: (s) => {
   384→      const state = s as OverlaySliceState;
   385→      Object.assign(state, initialOverlayState);
   386→    },
   387→  },
   388→});
   389→
   390→// =============================================================================
   391→// Data Loading Functions
   392→// =============================================================================
   393→
   394→/**
   395→ * Load man-hour overlay data from API
   396→ */
   397→export async function loadManhourOverlayData(
   398→  dispatch: {
   399→    setManhourLoading: (loading: boolean) => void;
   400→    setManhourData: (data: ManhourOverlayData) => void;
   401→    setManhourError: (error: string) => void;
   402→  },
   403→  options: { baseUrl?: string; weeks?: number; depotId?: string } = {}
   404→): Promise<void> {
   405→  const { baseUrl = '/api/v1', weeks = 12, depotId } = options;
   406→
   407→  dispatch.setManhourLoading(true);
   408→
   409→  const params = new URLSearchParams();
   410→  params.set('weeks', String(weeks));
   411→  if (depotId) {
   412→    params.set('depotId', depotId);
   413→  }
   414→
   415→  try {
   416→    const response = await fetch(`${baseUrl}/canvas/manhour-overlay?${params}`);
   417→
   418→    if (!response.ok) {
   419→      throw new Error(`Failed to fetch man-hour overlay: ${response.status}`);
   420→    }
   421→
   422→    const json = await response.json() as { data: ManhourOverlayData };
   423→    dispatch.setManhourData(json.data);
   424→  } catch (error) {
   425→    const message = error instanceof Error ? error.message : 'Unknown error';
   426→    dispatch.setManhourError(message);
   427→  }
   428→}
   429→
   430→/**
   431→ * Load drift overlay data from API
   432→ */
   433→export async function loadDriftOverlayData(
   434→  dispatch: {
   435→    setDriftLoading: (loading: boolean) => void;
   436→    setDriftData: (data: DriftOverlayData) => void;
   437→    setDriftError: (error: string) => void;
   438→  },
   439→  options: { baseUrl?: string; baselineId?: string } = {}
   440→): Promise<void> {
   441→  const { baseUrl = '/api/v1', baselineId } = options;
   442→
   443→  dispatch.setDriftLoading(true);
   444→
   445→  const params = new URLSearchParams();
   446→  if (baselineId) {
   447→    params.set('baselineId', baselineId);
   448→  }
   449→
   450→  try {
   451→    const response = await fetch(`${baseUrl}/canvas/drift-overlay?${params}`);
   452→
   453→    if (!response.ok) {
   454→      throw new Error(`Failed to fetch drift overlay: ${response.status}`);
   455→    }
   456→
   457→    const json = await response.json() as { data: DriftOverlayData };
   458→    dispatch.setDriftData(json.data);
   459→  } catch (error) {
   460→    const message = error instanceof Error ? error.message : 'Unknown error';
   461→    dispatch.setDriftError(message);
   462→  }
   463→}
   464→
   465→// =============================================================================
   466→// Selectors
   467→// =============================================================================
   468→
   469→/**
   470→ * Get filtered man-hour weeks based on depot filter
   471→ */
   472→export function selectFilteredManhourWeeks(state: OverlaySliceState): ManhourWeekData[] {
   473→  if (!state.manhourData) return [];
   474→
   475→  if (!state.manhourDepotFilter) {
   476→    return state.manhourData.weeks;
   477→  }
   478→
   479→  return state.manhourData.weeks.map(week => ({
   480→    ...week,
   481→    depots: week.depots.filter(d => d.depotId === state.manhourDepotFilter),
   482→  }));
   483→}
   484→
   485→/**
   486→ * Get weeks with overloaded status
   487→ */
   488→export function selectOverloadedWeeks(state: OverlaySliceState): ManhourWeekData[] {
   489→  if (!state.manhourData) return [];
   490→
   491→  return state.manhourData.weeks.filter(week =>
   492→    week.depots.some(d => d.status === 'OVERLOADED')
   493→  );
   494→}
   495→
   496→/**
   497→ * Get total overloaded hours across all weeks
   498→ */
   499→export function selectTotalOverloadedHours(state: OverlaySliceState): number {
   500→  if (!state.manhourData) return 0;
   501→
   502→  return state.manhourData.weeks.reduce((total, week) => {
   503→    return total + week.depots.reduce((weekTotal, depot) => {
   504→      if (depot.status === 'OVERLOADED') {
   505→        return weekTotal + (depot.requiredHours - depot.availableHours);
   506→      }
   507→      return weekTotal;
   508→    }, 0);
   509→  }, 0);
   510→}
   511→
   512→/**
   513→ * Get filtered trains based on drift severity filter
   514→ */
   515→export function selectFilteredDriftTrains(state: OverlaySliceState): TrainDriftData[] {
   516→  if (!state.driftData) return [];
   517→
   518→  if (!state.driftSeverityFilter) {
   519→    return state.driftData.trains;
   520→  }
   521→
   522→  return state.driftData.trains.filter(t => t.driftSeverity === state.driftSeverityFilter);
   523→}
   524→
   525→/**
   526→ * Get trains requiring replan (RED severity)
   527→ */
   528→export function selectTrainsRequiringReplan(state: OverlaySliceState): TrainDriftData[] {
   529→  if (!state.driftData) return [];
   530→  return state.driftData.trains.filter(t => t.driftSeverity === 'RED');
   531→}
   532→
   533→/**
   534→ * Get drift summary statistics
   535→ */
   536→export function selectDriftSummaryStats(state: OverlaySliceState): {
   537→  totalTrains: number;
   538→  greenCount: number;
   539→  yellowCount: number;
   540→  redCount: number;
   541→} {
   542→  if (!state.driftData) {
   543→    return { totalTrains: 0, greenCount: 0, yellowCount: 0, redCount: 0 };
   544→  }
   545→
   546→  const trains = state.driftData.trains;
   547→  return {
   548→    totalTrains: trains.length,
   549→    greenCount: trains.filter(t => t.driftSeverity === 'GREEN').length,
   550→    yellowCount: trains.filter(t => t.driftSeverity === 'YELLOW').length,
   551→    redCount: trains.filter(t => t.driftSeverity === 'RED').length,
   552→  };
   553→}
   554→
   555→/**
   556→ * Check if man-hour data is stale (>5 minutes)
   557→ */
   558→export function isManhourDataStale(state: OverlaySliceState): boolean {
   559→  if (!state.manhourLastFetch) return true;
   560→  return Date.now() - state.manhourLastFetch > 5 * 60 * 1000;
   561→}
   562→
   563→/**
   564→ * Check if drift data is stale (>5 minutes)
   565→ */
   566→export function isDriftDataStale(state: OverlaySliceState): boolean {
   567→  if (!state.driftLastFetch) return true;
   568→  return Date.now() - state.driftLastFetch > 5 * 60 * 1000;
   569→}
   570→
   571→/**
   572→ * Load baseline shadow overlay data from API
   573→ */
   574→export async function loadBaselineShadowData(
   575→  dispatch: {
   576→    setBaselineShadowLoading: (loading: boolean) => void;
   577→    setBaselineShadowData: (data: BaselineShadowData) => void;
   578→    setBaselineShadowError: (error: string) => void;
   579→  },
   580→  options: {
   581→    baseUrl?: string;
   582→    baselineId?: string;
   583→    fromDate?: string;
   584→    toDate?: string;
   585→    trainIds?: string[];
   586→  } = {}
   587→): Promise<void> {
   588→  const { baseUrl = '/api/v1', baselineId, fromDate, toDate, trainIds } = options;
   589→
   590→  dispatch.setBaselineShadowLoading(true);
   591→
   592→  const params = new URLSearchParams();
   593→  if (baselineId) {
   594→    params.set('baselineId', baselineId);
   595→  }
   596→  if (fromDate) {
   597→    params.set('fromDate', fromDate);
   598→  }
   599→  if (toDate) {
   600→    params.set('toDate', toDate);
   601→  }
   602→  if (trainIds && trainIds.length > 0) {
   603→    params.set('trainIds', trainIds.join(','));
   604→  }
   605→
   606→  try {
   607→    const response = await fetch(`${baseUrl}/canvas/baseline-shadow?${params}`);
   608→
   609→    if (!response.ok) {
   610→      throw new Error(`Failed to fetch baseline shadow: ${response.status}`);
   611→    }
   612→
   613→    const json = await response.json() as { data: BaselineShadowData };
   614→    dispatch.setBaselineShadowData(json.data);
   615→  } catch (error) {
   616→    const message = error instanceof Error ? error.message : 'Unknown error';
   617→    dispatch.setBaselineShadowError(message);
   618→  }
   619→}
   620→
   621→// =============================================================================
   622→// Baseline Shadow Selectors
   623→// =============================================================================
   624→
   625→/**
   626→ * Get filtered baseline PM blocks based on status filter
   627→ */
   628→export function selectFilteredBaselinePmBlocks(state: OverlaySliceState): BaselinePmBlock[] {
   629→  if (!state.baselineShadowData) return [];
   630→
   631→  if (!state.baselineShadowStatusFilter) {
   632→    return state.baselineShadowData.pmBlocks;
   633→  }
   634→
   635→  return state.baselineShadowData.pmBlocks.filter(
   636→    pm => pm.status === state.baselineShadowStatusFilter
   637→  );
   638→}
   639→
   640→/**
   641→ * Get PMs with significant drift (moved by more than N days)
   642→ */
   643→export function selectSignificantDriftPms(
   644→  state: OverlaySliceState,
   645→  thresholdDays: number = 7
   646→): BaselinePmBlock[] {
   647→  if (!state.baselineShadowData) return [];
   648→
   649→  return state.baselineShadowData.pmBlocks.filter(
   650→    pm => pm.status === 'MOVED' && Math.abs(pm.driftDays) > thresholdDays
   651→  );
   652→}
   653→
   654→/**
   655→ * Get baseline shadow summary statistics
   656→ */
   657→export function selectBaselineShadowSummary(state: OverlaySliceState): BaselineShadowData['summary'] | null {
   658→  return state.baselineShadowData?.summary ?? null;
   659→}
   660→
   661→/**
   662→ * Check if baseline shadow data is stale (>5 minutes)
   663→ */
   664→export function isBaselineShadowDataStale(state: OverlaySliceState): boolean {
   665→  if (!state.baselineShadowLastFetch) return true;
   666→  return Date.now() - state.baselineShadowLastFetch > 5 * 60 * 1000;
   667→}
