    // ==========================================================================
    // General Reducers
    // ==========================================================================

    reset: (s) => {
      const state = s as OverlaySliceState;
      Object.assign(state, initialOverlayState);
    },
  },
});

// =============================================================================
// Data Loading Functions
// =============================================================================

/**
 * Load man-hour overlay data from API
 */
export async function loadManhourOverlayData(
  dispatch: {
    setManhourLoading: (loading: boolean) => void;
    setManhourData: (data: ManhourOverlayData) => void;
    setManhourError: (error: string) => void;
  },
  options: { baseUrl?: string; weeks?: number; depotId?: string } = {}
): Promise<void> {
  const { baseUrl = '/api/v1', weeks = 12, depotId } = options;

  dispatch.setManhourLoading(true);

  const params = new URLSearchParams();
  params.set('weeks', String(weeks));
  if (depotId) {
    params.set('depotId', depotId);
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/manhour-overlay?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch man-hour overlay: ${response.status}`);
    }

    const json = await response.json() as { data: ManhourOverlayData };
    dispatch.setManhourData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setManhourError(message);
  }
}

/**
 * Load drift overlay data from API
 */
export async function loadDriftOverlayData(
  dispatch: {
    setDriftLoading: (loading: boolean) => void;
    setDriftData: (data: DriftOverlayData) => void;
    setDriftError: (error: string) => void;
  },
  options: { baseUrl?: string; baselineId?: string } = {}
): Promise<void> {
  const { baseUrl = '/api/v1', baselineId } = options;

  dispatch.setDriftLoading(true);

  const params = new URLSearchParams();
  if (baselineId) {
    params.set('baselineId', baselineId);
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/drift-overlay?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch drift overlay: ${response.status}`);
    }

    const json = await response.json() as { data: DriftOverlayData };
    dispatch.setDriftData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setDriftError(message);
  }
}

// =============================================================================
// Selectors
// =============================================================================

/**
 * Get filtered man-hour weeks based on depot filter
 */
export function selectFilteredManhourWeeks(state: OverlaySliceState): ManhourWeekData[] {
  if (!state.manhourData) return [];

  if (!state.manhourDepotFilter) {
    return state.manhourData.weeks;
  }

  return state.manhourData.weeks.map(week => ({
    ...week,
    depots: week.depots.filter(d => d.depotId === state.manhourDepotFilter),
  }));
}

/**
 * Get weeks with overloaded status
 */
export function selectOverloadedWeeks(state: OverlaySliceState): ManhourWeekData[] {
  if (!state.manhourData) return [];

  return state.manhourData.weeks.filter(week =>
    week.depots.some(d => d.status === 'OVERLOADED')
  );
}

/**
 * Get total overloaded hours across all weeks
 */
export function selectTotalOverloadedHours(state: OverlaySliceState): number {
  if (!state.manhourData) return 0;

  return state.manhourData.weeks.reduce((total, week) => {
    return total + week.depots.reduce((weekTotal, depot) => {
      if (depot.status === 'OVERLOADED') {
        return weekTotal + (depot.requiredHours - depot.availableHours);
      }
      return weekTotal;
    }, 0);
  }, 0);
}

/**
 * Get filtered trains based on drift severity filter
 */
export function selectFilteredDriftTrains(state: OverlaySliceState): TrainDriftData[] {
  if (!state.driftData) return [];

  if (!state.driftSeverityFilter) {
    return state.driftData.trains;
  }

  return state.driftData.trains.filter(t => t.driftSeverity === state.driftSeverityFilter);
}

/**
 * Get trains requiring replan (RED severity)
 */
export function selectTrainsRequiringReplan(state: OverlaySliceState): TrainDriftData[] {
  if (!state.driftData) return [];
  return state.driftData.trains.filter(t => t.driftSeverity === 'RED');
}

/**
 * Get drift summary statistics
 */
export function selectDriftSummaryStats(state: OverlaySliceState): {
  totalTrains: number;
  greenCount: number;
  yellowCount: number;
  redCount: number;
} {
  if (!state.driftData) {
    return { totalTrains: 0, greenCount: 0, yellowCount: 0, redCount: 0 };
  }

  const trains = state.driftData.trains;
  return {
    totalTrains: trains.length,
    greenCount: trains.filter(t => t.driftSeverity === 'GREEN').length,
    yellowCount: trains.filter(t => t.driftSeverity === 'YELLOW').length,
    redCount: trains.filter(t => t.driftSeverity === 'RED').length,
  };
}

/**
 * Check if man-hour data is stale (>5 minutes)
 */
export function isManhourDataStale(state: OverlaySliceState): boolean {
  if (!state.manhourLastFetch) return true;
  return Date.now() - state.manhourLastFetch > 5 * 60 * 1000;
}

/**
 * Check if drift data is stale (>5 minutes)
 */
export function isDriftDataStale(state: OverlaySliceState): boolean {
  if (!state.driftLastFetch) return true;
  return Date.now() - state.driftLastFetch > 5 * 60 * 1000;
}

/**
 * Load baseline shadow overlay data from API
 */
export async function loadBaselineShadowData(
  dispatch: {
    setBaselineShadowLoading: (loading: boolean) => void;
    setBaselineShadowData: (data: BaselineShadowData) => void;
    setBaselineShadowError: (error: string) => void;
  },
  options: {
    baseUrl?: string;
    baselineId?: string;
    fromDate?: string;
    toDate?: string;
    trainIds?: string[];
  } = {}
): Promise<void> {
  const { baseUrl = '/api/v1', baselineId, fromDate, toDate, trainIds } = options;

  dispatch.setBaselineShadowLoading(true);

  const params = new URLSearchParams();
  if (baselineId) {
    params.set('baselineId', baselineId);
  }
  if (fromDate) {
    params.set('fromDate', fromDate);
  }
  if (toDate) {
    params.set('toDate', toDate);
  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/baseline-shadow?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch baseline shadow: ${response.status}`);
    }

    const json = await response.json() as { data: BaselineShadowData };
    dispatch.setBaselineShadowData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setBaselineShadowError(message);
  }
}

// =============================================================================
// Baseline Shadow Selectors
// =============================================================================

/**
 * Get filtered baseline PM blocks based on status filter
 */
export function selectFilteredBaselinePmBlocks(state: OverlaySliceState): BaselinePmBlock[] {
  if (!state.baselineShadowData) return [];

  if (!state.baselineShadowStatusFilter) {
    return state.baselineShadowData.pmBlocks;
  }

  return state.baselineShadowData.pmBlocks.filter(
    pm => pm.status === state.baselineShadowStatusFilter
  );
}

/**
 * Get PMs with significant drift (moved by more than N days)
 */
export function selectSignificantDriftPms(
  state: OverlaySliceState,
  thresholdDays: number = 7
): BaselinePmBlock[] {
  if (!state.baselineShadowData) return [];

  return state.baselineShadowData.pmBlocks.filter(
    pm => pm.status === 'MOVED' && Math.abs(pm.driftDays) > thresholdDays
  );
}

/**
 * Get baseline shadow summary statistics
 */
export function selectBaselineShadowSummary(state: OverlaySliceState): BaselineShadowData['summary'] | null {
  return state.baselineShadowData?.summary ?? null;
}

/**
 * Check if baseline shadow data is stale (>5 minutes)
 */
export function isBaselineShadowDataStale(state: OverlaySliceState): boolean {
  if (!state.baselineShadowLastFetch) return true;
  return Date.now() - state.baselineShadowLastFetch > 5 * 60 * 1000;
}

