     1→/**
     2→ * Drift Analysis Routes
     3→ *
     4→ * REST endpoints for drift analysis monitoring.
     5→ * Drift analysis compares actual fleet state against published baselines
     6→ * to detect schedule and mileage deviations requiring attention.
     7→ *
     8→ * @see specs/005-api.md Section 5.9
     9→ */
    10→
    11→import { Hono } from 'hono';
    12→import {
    13→  success,
    14→  paginatedSuccess,
    15→  error,
    16→  parsePaginationQuery,
    17→  ErrorCodes,
    18→  type AppVariables,
    19→} from '../types';
    20→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    21→import {
    22→  getDriftMonitorService,
    23→  getBaselineService,
    24→  type DriftHistoryFilters,
    25→} from '../../services';
    26→import { isValidUuid } from '../../lib/schemas';
    27→
    28→// Singleton service instances
    29→let driftService: ReturnType<typeof getDriftMonitorService> | null = null;
    30→let baselineService: ReturnType<typeof getBaselineService> | null = null;
    31→
    32→function getDriftService(): ReturnType<typeof getDriftMonitorService> {
    33→  if (!driftService) {
    34→    driftService = getDriftMonitorService();
    35→  }
    36→  return driftService;
    37→}
    38→
    39→function getBaseline(): ReturnType<typeof getBaselineService> {
    40→  if (!baselineService) {
    41→    baselineService = getBaselineService();
    42→  }
    43→  return baselineService;
    44→}
    45→
    46→export const driftRoutes = new Hono<{ Variables: AppVariables }>();
    47→
    48→/**
    49→ * Map drift severity based on whether replan is required
    50→ */
    51→function getDriftSeverity(
    52→  mileageDriftPct: number,
    53→  maxPmDriftDays: number,
    54→  requiresReplan: boolean,
    55→  thresholds: { mileageDriftPct: number; scheduleDriftDays: number }
    56→): 'GREEN' | 'YELLOW' | 'RED' {
    57→  if (requiresReplan) {
    58→    return 'RED';
    59→  }
    60→
    61→  // Approaching threshold (>70% of threshold)
    62→  const mileageApproaching = Math.abs(mileageDriftPct) > thresholds.mileageDriftPct * 0.7;
    63→  const scheduleApproaching = maxPmDriftDays > thresholds.scheduleDriftDays * 0.7;
    64→
    65→  if (mileageApproaching || scheduleApproaching) {
    66→    return 'YELLOW';
    67→  }
    68→
    69→  return 'GREEN';
    70→}
    71→
    72→/**
    73→ * GET /drift/analysis
    74→ *
    75→ * Get drift analysis results comparing actual state against baseline.
    76→ * Returns the latest drift analysis with summary and per-train details.
    77→ *
    78→ * Query Parameters:
    79→ * - baselineId: Filter by specific baseline (UUID, optional - defaults to latest published)
    80→ * - trainId: Filter by specific train (UUID, optional)
    81→ * - requiresReplan: Filter trains requiring replan (boolean, optional)
    82→ * - page: Page number for train analyses (default: 1)
    83→ * - pageSize: Items per page (default: 50, max: 200)
    84→ */
    85→driftRoutes.get('/drift/analysis', async (c) => {
    86→  const requestId = getRequestId(c);
    87→  const service = getDriftService();
    88→  const baselines = getBaseline();
    89→
    90→  // Parse query parameters
    91→  const baselineIdParam = c.req.query('baselineId');
    92→  const trainIdParam = c.req.query('trainId');
    93→  const requiresReplanParam = c.req.query('requiresReplan');
    94→
    95→  // Validate UUIDs if provided
    96→  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    97→    return c.json(
    98→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
    99→      400
   100→    );
   101→  }
   102→
   103→  if (trainIdParam && !isValidUuid(trainIdParam)) {
   104→    return c.json(
   105→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId),
   106→      400
   107→    );
   108→  }
   109→
   110→  // Get baseline (specific or latest published)
   111→  let baseline;
   112→  if (baselineIdParam) {
   113→    try {
   114→      baseline = await baselines.getBaselineById(baselineIdParam);
   115→    } catch {
   116→      return c.json(
   117→        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
   118→        404
   119→      );
   120→    }
   121→  } else {
   122→    baseline = await baselines.getLatestBaseline();
   123→    if (!baseline) {
   124→      return c.json(
   125→        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
   126→        404
   127→      );
   128→    }
   129→  }
   130→
   131→  // Build filters for drift history query
   132→  const filters: DriftHistoryFilters = {
   133→    baselineId: baseline.id,
   134→  };
   135→
   136→  if (trainIdParam) {
   137→    filters.trainId = trainIdParam;
   138→  }
   139→
   140→  if (requiresReplanParam !== undefined) {
   141→    filters.requiresReplan = requiresReplanParam === 'true';
   142→  }
   143→
   144→  // Parse pagination
   145→  const pagination = parsePaginationQuery({
   146→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   147→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   148→  });
   149→
   150→  // Get drift summary
   151→  const summary = await service.getDriftSummary(baseline.id);
   152→
   153→  // Get drift history (train analyses)
   154→  const driftHistory = await service.getDriftHistory(filters, {
   155→    page: pagination.page,
   156→    pageSize: pagination.pageSize,
   157→  });
   158→
   159→  // Get current thresholds for severity calculation
   160→  const thresholds = service.getThresholds();
   161→
   162→  // Map to API response format per spec 005.9
   163→  const trainAnalyses = driftHistory.data.map((drift) => ({
   164→    trainId: drift.trainId,
   165→    trainNumber: null, // Would need train lookup for number
   166→    baselineProjectedKm: drift.baselineProjectedKm,
   167→    actualKm: drift.actualKm,
   168→    mileageDriftKm: drift.actualKm - drift.baselineProjectedKm,
   169→    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   170→    pmDrifts: [], // PM drift details would need to be stored/retrieved separately
   171→    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
   172→    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
   173→    requiresReplan: drift.requiresReplan,
   174→    replanReason: drift.replanReason,
   175→    driftSeverity: getDriftSeverity(
   176→      drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   177→      drift.maxPmDriftDays ?? 0,
   178→      drift.requiresReplan ?? false,
   179→      thresholds
   180→    ),
   181→  }));
   182→
   183→  // Build response
   184→  const responseData = {
   185→    baselineId: baseline.id,
   186→    baselineName: baseline.name,
   187→    baselineVersion: baseline.version,
   188→    analysisDate: driftHistory.data[0]?.analysisDate ?? null,
   189→    summary: summary
   190→      ? {
   191→          totalTrains: summary.totalTrains,
   192→          trainsWithDrift: summary.trainsWithDrift,
   193→          trainsRequiringReplan: summary.trainsRequiringReplan,
   194→          avgFleetDriftPct: Math.round(summary.avgMileageDriftPct * 100) / 100,
   195→          maxMileageDriftPct: Math.round(summary.maxMileageDriftPct * 100) / 100,
   196→          avgPmDriftDays: Math.round(summary.avgPmDriftDays * 10) / 10,
   197→          maxPmDriftDays: summary.maxPmDriftDays,
   198→        }
   199→      : {
   200→          totalTrains: 0,
   201→          trainsWithDrift: 0,
   202→          trainsRequiringReplan: 0,
   203→          avgFleetDriftPct: 0,
   204→          maxMileageDriftPct: 0,
   205→          avgPmDriftDays: 0,
   206→          maxPmDriftDays: 0,
   207→        },
   208→    trainAnalyses,
   209→  };
   210→
   211→  // Return paginated response if filtering by train or paginating through results
   212→  if (driftHistory.total > driftHistory.pageSize) {
   213→    return c.json(
   214→      paginatedSuccess(
   215→        [responseData],
   216→        {
   217→          page: driftHistory.page,
   218→          pageSize: driftHistory.pageSize,
   219→          totalItems: driftHistory.total,
   220→        },
   221→        { durationMs: getRequestDuration(c) }
   222→      )
   223→    );
   224→  }
   225→
   226→  return c.json(
   227→    success(responseData, {
   228→      timing: { durationMs: getRequestDuration(c) },
   229→    })
   230→  );
   231→});
