   235→
   236→  const conditions = [
   237→    gte(pmSchedule.targetDate, fromDate),
   238→    lte(pmSchedule.targetDate, toDate),
   239→    isNull(pmSchedule.scenarioId),
   240→  ];
   241→
   242→  if (trainIds.length > 0) {
