/**
 * Canvas Data Routes
 *
 * REST endpoints for Canvas visualization data.
 * Provides strategic (yearly), tactical (weekly), and overlay data
 * for the scheduling canvas UI component.
 *
 * Canvas Views:
 * - Strategic: Yearly PM aggregates per train for heatmap display
 * - Tactical: Weekly PM blocks with constraint walls for detailed scheduling
 * - Man-hour overlay: Depot workload utilization by week
 * - Drift overlay: Train drift severity relative to baseline
 *
 * @see specs/005-api.md Section 5.13
 */

import { Hono } from 'hono';
import { and, desc, eq, gte, inArray, isNull, lte, sql } from 'drizzle-orm';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { db } from '../../lib/db/connection';
import {
  trains,
  fleets,
  pmSchedule,
  pmTypes,
  tracks,
  depots,
  manhourProjections,
  manhourAdjustments,
  driftAnalysis,
  planBaselines,
} from '../../lib/db/schema';
import { isValidUuid } from '../../lib/schemas';

export const canvasRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /canvas/strategic
 *
 * Get strategic-level canvas data with yearly PM aggregates.
 * Used for the heatmap view showing PM density over multi-year horizons.
 *
 * Query Parameters:
 * - fleetId: Filter by fleet (UUID, optional)
 * - fromYear: Start year (number, defaults to current year)
 * - toYear: End year (number, defaults to current year + 10)
 */
canvasRoutes.get('/canvas/strategic', async (c) => {
  const requestId = getRequestId(c);

  const fleetIdParam = c.req.query('fleetId');
  const fromYearParam = c.req.query('fromYear');
  const toYearParam = c.req.query('toYear');

  if (fleetIdParam && !isValidUuid(fleetIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId),
      400
    );
  }

  const currentYear = new Date().getFullYear();
  const fromYear = fromYearParam ? parseInt(fromYearParam, 10) : currentYear;
  const toYear = toYearParam ? parseInt(toYearParam, 10) : currentYear + 10;

  if (isNaN(fromYear) || isNaN(toYear) || fromYear > toYear) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid year range', requestId),
      400
    );
  }

  const fromDate = `${fromYear}-01-01`;
  const toDate = `${toYear}-12-31`;

  const conditions = [
    gte(pmSchedule.targetDate, fromDate),
    lte(pmSchedule.targetDate, toDate),
    isNull(pmSchedule.scenarioId),
  ];

  if (fleetIdParam) {
    conditions.push(eq(trains.fleetId, fleetIdParam));
  }

  const results = await db
    .select({
      trainId: trains.id,
      trainNumber: trains.trainNumber,
      fleetId: trains.fleetId,
      fleetCode: fleets.code,
      year: sql<number>`EXTRACT(YEAR FROM ${pmSchedule.targetDate})::integer`.as('year'),
      pmCount: sql<number>`COUNT(${pmSchedule.id})::integer`.as('pm_count'),
      totalHours: sql<string>`COALESCE(SUM(${pmSchedule.assignedHours}), 0)`.as('total_hours'),
      completedCount: sql<number>`COUNT(CASE WHEN ${pmSchedule.status} = 'COMPLETED' THEN 1 END)::integer`.as('completed_count'),
      lockedCount: sql<number>`COUNT(CASE WHEN ${pmSchedule.isLocked} = true THEN 1 END)::integer`.as('locked_count'),
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .where(and(...conditions))
    .groupBy(
      trains.id,
      trains.trainNumber,
      trains.fleetId,
      fleets.code,
      sql`EXTRACT(YEAR FROM ${pmSchedule.targetDate})`
    )
    .orderBy(trains.trainNumber, sql`year`);

  const trainMap = new Map<string, {
    trainId: string;
    trainNumber: string;
    fleetCode: string;
    years: Array<{
      year: number;
      pmCount: number;
      totalHours: number;
      completedCount: number;
      lockedCount: number;
    }>;
  }>();

  let maxPmCount = 0;
  let maxHours = 0;

  for (const row of results) {
    const hours = parseFloat(row.totalHours) || 0;
    maxPmCount = Math.max(maxPmCount, row.pmCount);
    maxHours = Math.max(maxHours, hours);

    if (!trainMap.has(row.trainId)) {
      trainMap.set(row.trainId, {
        trainId: row.trainId,
        trainNumber: row.trainNumber,
        fleetCode: row.fleetCode,
        years: [],
      });
    }

    trainMap.get(row.trainId)!.years.push({
      year: row.year,
      pmCount: row.pmCount,
      totalHours: Math.round(hours * 10) / 10,
      completedCount: row.completedCount,
      lockedCount: row.lockedCount,
    });
  }

  return c.json(
    success(
      {
        trains: Array.from(trainMap.values()),
        heatmapData: {
          maxPmCount,
          maxHours: Math.round(maxHours * 10) / 10,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/tactical
 *
 * Get tactical-level canvas data with weekly PM blocks.
 * Used for the detailed scheduling view with drag-and-drop PM movement.
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromWeek: Start date of first week (ISO date, defaults to today)
 * - toWeek: End date of last week (ISO date, defaults to +12 weeks)
 */
canvasRoutes.get('/canvas/tactical', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromWeekParam = c.req.query('fromWeek');
  const toWeekParam = c.req.query('toWeek');

  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];

  for (const id of trainIds) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  const today = new Date();
  const defaultFromWeek = new Date(today);
  defaultFromWeek.setDate(today.getDate() - today.getDay());

  const defaultToWeek = new Date(defaultFromWeek);
  defaultToWeek.setDate(defaultToWeek.getDate() + 12 * 7);

  let fromWeek: Date;
  let toWeek: Date;

  if (fromWeekParam) {
    fromWeek = new Date(fromWeekParam);
    if (isNaN(fromWeek.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromWeek date format', requestId),
        400
      );
    }
  } else {
    fromWeek = defaultFromWeek;
  }

  if (toWeekParam) {
    toWeek = new Date(toWeekParam);
    if (isNaN(toWeek.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toWeek date format', requestId),
        400
      );
    }
  } else {
    toWeek = defaultToWeek;
  }

  const fromDate = fromWeek.toISOString().split('T')[0];
  const toDate = toWeek.toISOString().split('T')[0];

  const conditions = [
    gte(pmSchedule.targetDate, fromDate),
    lte(pmSchedule.targetDate, toDate),
    isNull(pmSchedule.scenarioId),
  ];

  if (trainIds.length > 0) {
    conditions.push(inArray(pmSchedule.trainId, trainIds));
  }

  const results = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      trainNumber: trains.trainNumber,
      pmCode: pmTypes.pmCode,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      isLocked: pmSchedule.isLocked,
      trackNumber: tracks.trackNumber,
      depotCode: depots.code,
      displayColor: pmTypes.displayColor,
      estimatedHours: pmTypes.estimatedHours,
      minTrackDays: pmTypes.minTrackDays,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .where(and(...conditions))
    .orderBy(pmSchedule.targetDate);

  const pmBlocks = results.map((row) => ({
    pmId: row.pmId,
    trainId: row.trainId,
    trainNumber: row.trainNumber,
    pmCode: row.pmCode,
    targetDate: row.targetDate,
    durationDays: row.minTrackDays ?? 1,
    status: row.status,
    constraintStart: row.constraintStart,
    constraintEnd: row.constraintEnd,
    isLocked: row.isLocked ?? false,
    trackNumber: row.trackNumber,
    depotCode: row.depotCode,
    displayColor: row.displayColor ?? '#3B82F6',
    estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
  }));

  const constraintWalls: Array<{
    pmId: string;
    type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
    date: string;
  }> = [];

  for (const pm of results) {
    constraintWalls.push(
      { pmId: pm.pmId, type: 'COMPLIANCE_START', date: pm.constraintStart },
      { pmId: pm.pmId, type: 'COMPLIANCE_END', date: pm.constraintEnd }
    );
  }

  return c.json(
    success(
      {
        pmBlocks,
        constraintWalls,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/tactical-wide
 *
 * Get tactical-wide canvas data with monthly PM blocks.
 * Used for the compressed Gantt view bridging strategic and tactical views.
 * Shows 1-year of PM data at monthly granularity.
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromDate: Start date (ISO date, defaults to start of current month)
 * - toDate: End date (ISO date, defaults to +12 months)
 *
 * @see specs/006-user-interface.md Section 6.3.1 (Tactical-Wide zoom level 4-8)
 */
canvasRoutes.get('/canvas/tactical-wide', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');

  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];

  for (const id of trainIds) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  // Default to 12 months starting from current month
  const today = new Date();
  const defaultFromDate = new Date(today.getFullYear(), today.getMonth(), 1);
  const defaultToDate = new Date(defaultFromDate);
  defaultToDate.setMonth(defaultToDate.getMonth() + 12);

  let fromDate: Date;
  let toDate: Date;

  if (fromDateParam) {
    fromDate = new Date(fromDateParam);
    if (isNaN(fromDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
        400
      );
    }
  } else {
    fromDate = defaultFromDate;
  }

  if (toDateParam) {
    toDate = new Date(toDateParam);
    if (isNaN(toDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
        400
      );
    }
  } else {
    toDate = defaultToDate;
  }

  const fromDateStr = fromDate.toISOString().split('T')[0];
  const toDateStr = toDate.toISOString().split('T')[0];

  // Fetch trains for the response
  const trainConditions = trainIds.length > 0
    ? [inArray(trains.id, trainIds)]
    : [];

  const trainsResult = await db
    .select({
      trainId: trains.id,
      trainNumber: trains.trainNumber,
      fleetCode: fleets.code,
    })
    .from(trains)
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .where(trainConditions.length > 0 ? and(...trainConditions) : undefined)
    .orderBy(trains.trainNumber);

  // Fetch PM blocks for the date range
  const pmConditions = [
    gte(pmSchedule.targetDate, fromDateStr),
    lte(pmSchedule.targetDate, toDateStr),
    isNull(pmSchedule.scenarioId),
  ];

  if (trainIds.length > 0) {
    pmConditions.push(inArray(pmSchedule.trainId, trainIds));
  }

  const pmResults = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      pmCode: pmTypes.pmCode,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      isLocked: pmSchedule.isLocked,
      displayColor: pmTypes.displayColor,
      minTrackDays: pmTypes.minTrackDays,
    })
    .from(pmSchedule)
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .where(and(...pmConditions))
    .orderBy(pmSchedule.targetDate);

  // Transform trains response
  const trainsList = trainsResult.map((row) => ({
    trainId: row.trainId,
    trainNumber: row.trainNumber,
    fleetCode: row.fleetCode,
  }));

  // Transform PM blocks (simplified for tactical-wide view)
  const pmBlocks = pmResults.map((row) => ({
    pmId: row.pmId,
    trainId: row.trainId,
    pmCode: row.pmCode,
    targetDate: row.targetDate,
    durationDays: row.minTrackDays ?? 1,
    status: row.status,
    isLocked: row.isLocked ?? false,
    displayColor: row.displayColor ?? '#3B82F6',
  }));

  return c.json(
    success(
      {
        trains: trainsList,
        pmBlocks,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/operational
 *
 * Get operational-level canvas data with detailed PM cards.
 * Used for the 4-week operational view with material status.
 * Zoom levels 12-16 (daily granularity).
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromDate: Start date (ISO date, defaults to start of current week)
 * - toDate: End date (ISO date, defaults to +4 weeks)
 *
 * @see specs/006-user-interface.md Section 6.3.4 (Operational zoom level 12-16)
 */
canvasRoutes.get('/canvas/operational', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');

  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];

  for (const id of trainIds) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  // Default to 4 weeks starting from current week
  const today = new Date();
  const defaultFromDate = new Date(today);
  defaultFromDate.setDate(today.getDate() - today.getDay()); // Start of week
  const defaultToDate = new Date(defaultFromDate);
  defaultToDate.setDate(defaultToDate.getDate() + 4 * 7); // 4 weeks ahead

  let fromDate: Date;
  let toDate: Date;

  if (fromDateParam) {
    fromDate = new Date(fromDateParam);
    if (isNaN(fromDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
        400
      );
    }
  } else {
    fromDate = defaultFromDate;
  }

  if (toDateParam) {
    toDate = new Date(toDateParam);
    if (isNaN(toDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
        400
      );
    }
  } else {
    toDate = defaultToDate;
  }

  const fromDateStr = fromDate.toISOString().split('T')[0];
  const toDateStr = toDate.toISOString().split('T')[0];

  // Fetch PM blocks with detailed information
  const pmConditions = [
    gte(pmSchedule.targetDate, fromDateStr),
    lte(pmSchedule.targetDate, toDateStr),
    isNull(pmSchedule.scenarioId),
  ];

  if (trainIds.length > 0) {
    pmConditions.push(inArray(pmSchedule.trainId, trainIds));
  }

  const pmResults = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      trainNumber: trains.trainNumber,
      fleetCode: fleets.code,
      pmCode: pmTypes.pmCode,
      pmName: pmTypes.pmName,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      isLocked: pmSchedule.isLocked,
      trackNumber: tracks.trackNumber,
      depotCode: depots.code,
      displayColor: pmTypes.displayColor,
      estimatedHours: pmTypes.estimatedHours,
      minTrackDays: pmTypes.minTrackDays,
      assignedShift: pmSchedule.assignedShift,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .where(and(...pmConditions))
    .orderBy(pmSchedule.targetDate);

  // Transform PM blocks with detailed information
  const pmBlocks = pmResults.map((row) => {
    const durationDays = row.minTrackDays ?? 1;
    const targetDate = new Date(row.targetDate);
    const endDate = new Date(targetDate);
    endDate.setDate(targetDate.getDate() + durationDays - 1);

    return {
      pmId: row.pmId,
      trainId: row.trainId,
      trainNumber: row.trainNumber,
      fleetCode: row.fleetCode,
      pmCode: row.pmCode,
      pmDescription: row.pmName ?? row.pmCode,
      targetDate: row.targetDate,
      endDate: endDate.toISOString().split('T')[0],
      durationDays,
      status: row.status,
      constraintStart: row.constraintStart,
      constraintEnd: row.constraintEnd,
      isLocked: row.isLocked ?? false,
      trackNumber: row.trackNumber,
      depotCode: row.depotCode,
      estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
      assignedShift: row.assignedShift,
      // Material requirements are fetched separately if needed
      // For now return empty array - can be expanded when inventory integration is complete
      materials: [] as Array<{
        materialId: string;
        materialName: string;
        quantityRequired: number;
        quantityAvailable: number;
        status: 'AVAILABLE' | 'LOW_STOCK' | 'UNAVAILABLE' | 'ARRIVING';
        arrivalDate?: string;
      }>,
      displayColor: row.displayColor ?? '#3B82F6',
    };
  });

  return c.json(
    success(
      {
        pmBlocks,
        dateRange: {
          fromDate: fromDateStr,
          toDate: toDateStr,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/manhour-overlay
 *
 * Get man-hour overlay data showing depot workload by week.
 * Used to visualize resource utilization in the canvas sidebar.
 *
 * Query Parameters:
 * - depotId: Filter by depot (UUID, optional)
 * - weeks: Number of weeks to include (default: 12)
 */
canvasRoutes.get('/canvas/manhour-overlay', async (c) => {
  const requestId = getRequestId(c);

  const depotIdParam = c.req.query('depotId');
  const weeksParam = c.req.query('weeks');

  if (depotIdParam && !isValidUuid(depotIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depot ID format', requestId),
      400
    );
  }

  const numWeeks = weeksParam ? parseInt(weeksParam, 10) : 12;
  if (isNaN(numWeeks) || numWeeks < 1 || numWeeks > 52) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Weeks must be between 1 and 52', requestId),
      400
    );
  }

  const latestRunResult = await db
    .select({ projectionRunId: manhourProjections.projectionRunId })
    .from(manhourProjections)
    .orderBy(desc(manhourProjections.createdAt))
    .limit(1);

  if (latestRunResult.length === 0) {
    return c.json(
      success(
        { weeks: [] },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  const latestRunId = latestRunResult[0].projectionRunId;

  const conditions = [
    eq(manhourProjections.projectionRunId, latestRunId),
    eq(manhourProjections.granularity, 'WEEKLY'),
  ];

  if (depotIdParam) {
    conditions.push(eq(manhourProjections.depotId, depotIdParam));
  }

  const projections = await db
    .select({
      projectionId: manhourProjections.id,
      depotId: manhourProjections.depotId,
      depotCode: depots.code,
      periodStart: manhourProjections.periodStart,
      periodEnd: manhourProjections.periodEnd,
      requiredHours: manhourProjections.requiredTotalHours,
      availableHours: manhourProjections.availableTotalHours,
    })
    .from(manhourProjections)
    .innerJoin(depots, eq(manhourProjections.depotId, depots.id))
    .where(and(...conditions))
    .orderBy(manhourProjections.periodStart, depots.code)
    .limit(numWeeks * 10);

  const adjustmentsResult = await db
    .select({
      projectionId: manhourAdjustments.projectionId,
      adjustmentType: manhourAdjustments.adjustmentType,
      hoursAdjusted: manhourAdjustments.hoursAdjusted,
      status: manhourAdjustments.status,
    })
    .from(manhourAdjustments)
    .where(
      and(
        inArray(
          manhourAdjustments.projectionId,
          projections.map((p) => p.projectionId)
        ),
        eq(manhourAdjustments.status, 'PROPOSED')
      )
    );

  const adjustmentsByProjection = new Map<string, typeof adjustmentsResult>();
  for (const adj of adjustmentsResult) {
    if (!adjustmentsByProjection.has(adj.projectionId)) {
      adjustmentsByProjection.set(adj.projectionId, []);
    }
    adjustmentsByProjection.get(adj.projectionId)!.push(adj);
  }

  const weekMap = new Map<string, {
    weekStart: string;
    depots: Array<{
      depotId: string;
      depotCode: string;
      requiredHours: number;
      availableHours: number;
      utilizationPct: number;
      status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
      adjustments: Array<{
        type: string;
        hours: number;
        status: string;
      }>;
    }>;
  }>();

  for (const proj of projections) {
    const weekStart = proj.periodStart;
    const required = parseFloat(proj.requiredHours);
    const available = parseFloat(proj.availableHours);
    const utilizationPct = available > 0 ? (required / available) * 100 : 0;

    let status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
    if (required > available) {
      status = 'OVERLOADED';
    } else if (utilizationPct < 70) {
      status = 'UNDERUTILIZED';
    } else {
      status = 'OPTIMAL';
    }

    const adjustments = (adjustmentsByProjection.get(proj.projectionId) || []).map((a) => ({
      type: a.adjustmentType,
      hours: parseFloat(a.hoursAdjusted),
      status: a.status ?? 'PROPOSED',
    }));

    if (!weekMap.has(weekStart)) {
      weekMap.set(weekStart, { weekStart, depots: [] });
    }

    weekMap.get(weekStart)!.depots.push({
      depotId: proj.depotId,
      depotCode: proj.depotCode,
      requiredHours: Math.round(required * 10) / 10,
      availableHours: Math.round(available * 10) / 10,
      utilizationPct: Math.round(utilizationPct * 10) / 10,
      status,
      adjustments,
    });
  }

  const weeks = Array.from(weekMap.values()).sort(
    (a, b) => a.weekStart.localeCompare(b.weekStart)
  );

  return c.json(
    success(
      { weeks },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/detail
 *
 * Get detail-level canvas data with full PM information.
 * Used for the detail view (zoom 16+) with rich editing capabilities.
 * Includes change history, constraint validation, and crew assignments.
 *
 * Query Parameters:
 * - trainIds: Comma-separated train IDs (UUID[], optional - defaults to all)
 * - fromDate: Start date (ISO date, defaults to start of current week)
 * - toDate: End date (ISO date, defaults to +1 week)
 *
 * @see specs/006-user-interface.md Section 6.3.4, 6.3.5 (Detail zoom level 16+)
 */
canvasRoutes.get('/canvas/detail', async (c) => {
  const requestId = getRequestId(c);

  const trainIdsParam = c.req.query('trainIds');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');

  const trainIds = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];

  for (const id of trainIds) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  // Default to 1 week starting from current week (for detailed view)
  const today = new Date();
  const defaultFromDate = new Date(today);
  defaultFromDate.setDate(today.getDate() - today.getDay()); // Start of week
  const defaultToDate = new Date(defaultFromDate);
  defaultToDate.setDate(defaultToDate.getDate() + 7); // 1 week ahead

  let fromDate: Date;
  let toDate: Date;

  if (fromDateParam) {
    fromDate = new Date(fromDateParam);
    if (isNaN(fromDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
        400
      );
    }
  } else {
    fromDate = defaultFromDate;
  }

  if (toDateParam) {
    toDate = new Date(toDateParam);
    if (isNaN(toDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
        400
      );
    }
  } else {
    toDate = defaultToDate;
  }

  const fromDateStr = fromDate.toISOString().split('T')[0];
  const toDateStr = toDate.toISOString().split('T')[0];

  // Fetch PM blocks with detailed information
  const pmConditions = [
    gte(pmSchedule.targetDate, fromDateStr),
    lte(pmSchedule.targetDate, toDateStr),
    isNull(pmSchedule.scenarioId),
  ];

  if (trainIds.length > 0) {
    pmConditions.push(inArray(pmSchedule.trainId, trainIds));
  }

  const pmResults = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      trainNumber: trains.trainNumber,
      fleetCode: fleets.code,
      pmCode: pmTypes.pmCode,
      pmName: pmTypes.pmName,
      targetDate: pmSchedule.targetDate,
      status: pmSchedule.status,
      constraintStart: pmSchedule.constraintStart,
      constraintEnd: pmSchedule.constraintEnd,
      isLocked: pmSchedule.isLocked,
      trackNumber: tracks.trackNumber,
      depotCode: depots.code,
      displayColor: pmTypes.displayColor,
      estimatedHours: pmTypes.estimatedHours,
      minTrackDays: pmTypes.minTrackDays,
      assignedShift: pmSchedule.assignedShift,
      createdAt: pmSchedule.createdAt,
      updatedAt: pmSchedule.updatedAt,
    })
    .from(pmSchedule)
    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
    .where(and(...pmConditions))
    .orderBy(pmSchedule.targetDate);

  // Transform PM blocks with full detail information
  const pmBlocks = pmResults.map((row) => {
    const durationDays = row.minTrackDays ?? 1;
    const targetDate = new Date(row.targetDate);
    const endDate = new Date(targetDate);
    endDate.setDate(targetDate.getDate() + durationDays - 1);

    // Mock change history (in production, this would come from audit trail)
    type ChangeHistoryChangeType = 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
    const changeHistory: Array<{
      id: string;
      timestamp: string;
      changeType: ChangeHistoryChangeType;
      userId: string;
      userName: string;
      reason?: string;
    }> = [
      {
        id: `${row.pmId}-create`,
        timestamp: row.createdAt?.toISOString() ?? new Date().toISOString(),
        changeType: 'CREATE',
        userId: 'system',
        userName: 'System',
        reason: 'Initial PM scheduling',
      },
    ];

    // Add update entry if updatedAt differs from createdAt
    if (row.updatedAt && row.createdAt && row.updatedAt.getTime() !== row.createdAt.getTime()) {
      changeHistory.push({
        id: `${row.pmId}-update`,
        timestamp: row.updatedAt.toISOString(),
        changeType: 'MOVE',
        userId: 'system',
        userName: 'System',
        reason: 'PM updated',
      });
    }

    // Calculate constraint validation
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const constraintEnd = new Date(row.constraintEnd);
    const daysToDeadline = Math.floor((constraintEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

    const violations: Array<{
      type: 'HARD' | 'SOFT';
      constraint: string;
      message: string;
      canOverride: boolean;
    }> = [];

    const warnings: Array<{
      type: string;
      message: string;
    }> = [];

    if (daysToDeadline < 0) {
      violations.push({
        type: 'HARD',
        constraint: 'Compliance Window',
        message: `PM is ${Math.abs(daysToDeadline)} days past compliance deadline`,
        canOverride: false,
      });
    } else if (daysToDeadline < 7) {
      warnings.push({
        type: 'COMPLIANCE_WARNING',
        message: `Compliance window closes in ${daysToDeadline} days`,
      });
    }

    return {
      pmId: row.pmId,
      trainId: row.trainId,
      trainNumber: row.trainNumber,
      fleetCode: row.fleetCode,
      pmCode: row.pmCode,
      pmDescription: row.pmName ?? row.pmCode,
      targetDate: row.targetDate,
      endDate: endDate.toISOString().split('T')[0],
      durationDays,
      status: row.status,
      constraintStart: row.constraintStart,
      constraintEnd: row.constraintEnd,
      isLocked: row.isLocked ?? false,
      trackNumber: row.trackNumber,
      depotCode: row.depotCode,
      estimatedHours: row.estimatedHours ? parseFloat(row.estimatedHours) : null,
      assignedShift: row.assignedShift,
      // Material requirements - empty for now, can be populated from inventory integration
      materials: [] as Array<{
        materialId: string;
        materialName: string;
        quantityRequired: number;
        quantityAvailable: number;
        status: 'AVAILABLE' | 'LOW_STOCK' | 'UNAVAILABLE' | 'ARRIVING';
        arrivalDate?: string;
      }>,
      displayColor: row.displayColor ?? '#3B82F6',
      // Detail-specific fields
      changeHistory,
      constraintValidation: {
        isValid: violations.length === 0,
        violations,
        warnings,
      },
      assignedCrew: [] as Array<{
        crewId: string;
        crewName: string;
        role: string;
        shift: string;
      }>,
    };
  });

  return c.json(
    success(
      {
        pmBlocks,
        dateRange: {
          fromDate: fromDateStr,
          toDate: toDateStr,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/drift-overlay
 *
 * Get drift overlay data showing train drift severity relative to baseline.
 * Used to highlight trains requiring attention in the canvas.
 *
 * Query Parameters:
 * - baselineId: Baseline to compare against (UUID, optional - defaults to latest published)
 */
canvasRoutes.get('/canvas/drift-overlay', async (c) => {
  const requestId = getRequestId(c);

  const baselineIdParam = c.req.query('baselineId');

  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  let baseline;
  if (baselineIdParam) {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.id, baselineIdParam))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
    baseline = result[0];
  } else {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.status, 'PUBLISHED'))
      .orderBy(desc(planBaselines.publishedAt))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
    baseline = result[0];
  }

  const latestAnalysisResult = await db
    .select({ analysisDate: driftAnalysis.analysisDate })
    .from(driftAnalysis)
    .where(eq(driftAnalysis.baselineId, baseline.id))
    .orderBy(desc(driftAnalysis.analysisDate))
    .limit(1);

  if (latestAnalysisResult.length === 0) {
    return c.json(
      success(
        {
          baselineId: baseline.id,
          baselineName: baseline.name,
          trains: [],
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  const latestDate = latestAnalysisResult[0].analysisDate;

  const driftResults = await db
    .select({
      trainId: driftAnalysis.trainId,
      trainNumber: trains.trainNumber,
      baselineProjectedKm: driftAnalysis.baselineProjectedKm,
      actualKm: driftAnalysis.actualKm,
      mileageDriftPct: driftAnalysis.mileageDriftPct,
      avgPmDriftDays: driftAnalysis.avgPmDriftDays,
      maxPmDriftDays: driftAnalysis.maxPmDriftDays,
      requiresReplan: driftAnalysis.requiresReplan,
    })
    .from(driftAnalysis)
    .innerJoin(trains, eq(driftAnalysis.trainId, trains.id))
    .where(
      and(
        eq(driftAnalysis.baselineId, baseline.id),
        eq(driftAnalysis.analysisDate, latestDate)
      )
    )
    .orderBy(trains.trainNumber);

  const thresholds = {
    mileageDriftPct: 5.0,
    scheduleDriftDays: 14,
  };

  const trainDrifts = driftResults.map((drift) => {
    const mileagePct = drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0;
    const maxPmDays = drift.maxPmDriftDays ?? 0;

    let driftSeverity: 'GREEN' | 'YELLOW' | 'RED';
    if (drift.requiresReplan) {
      driftSeverity = 'RED';
    } else if (
      Math.abs(mileagePct) > thresholds.mileageDriftPct * 0.7 ||
      maxPmDays > thresholds.scheduleDriftDays * 0.7
    ) {
      driftSeverity = 'YELLOW';
    } else {
      driftSeverity = 'GREEN';
    }

    return {
      trainId: drift.trainId,
      trainNumber: drift.trainNumber,
      driftSeverity,
      mileageDriftPct: Math.round(mileagePct * 100) / 100,
      pmDrifts: [],
    };
  });

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        trains: trainDrifts,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /canvas/baseline-shadow
 *
 * Get baseline shadow overlay data showing PM positions from baseline vs current.
 * Used to render shadow blocks behind current PM positions on the canvas.
 *
 * Query Parameters:
 * - baselineId: Baseline to compare against (UUID, optional - defaults to latest published)
 * - fromDate: Start date for PM blocks (ISO date, optional - defaults to today)
 * - toDate: End date for PM blocks (ISO date, optional - defaults to +12 weeks)
 * - trainIds: Comma-separated train IDs to filter (optional)
 */
canvasRoutes.get('/canvas/baseline-shadow', async (c) => {
  const requestId = getRequestId(c);

  const baselineIdParam = c.req.query('baselineId');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');
  const trainIdsParam = c.req.query('trainIds');

  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  const trainIdFilter = trainIdsParam ? trainIdsParam.split(',').map((id) => id.trim()) : [];
  for (const id of trainIdFilter) {
    if (!isValidUuid(id)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, `Invalid train ID format: ${id}`, requestId),
        400
      );
    }
  }

  // Get baseline (specified or latest published)
  let baseline;
  if (baselineIdParam) {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.id, baselineIdParam))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
    baseline = result[0];
  } else {
    const result = await db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.status, 'PUBLISHED'))
      .orderBy(desc(planBaselines.publishedAt))
      .limit(1);

    if (result.length === 0) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
    baseline = result[0];
  }

  // Calculate date range
  const today = new Date();
  const defaultFromDate = new Date(today);
  const defaultToDate = new Date(today);
  defaultToDate.setDate(defaultToDate.getDate() + 12 * 7); // 12 weeks

  let fromDate: Date;
  let toDate: Date;

  if (fromDateParam) {
    fromDate = new Date(fromDateParam);
    if (isNaN(fromDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid fromDate format', requestId),
        400
      );
    }
  } else {
    fromDate = defaultFromDate;
  }

  if (toDateParam) {
    toDate = new Date(toDateParam);
    if (isNaN(toDate.getTime())) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Invalid toDate format', requestId),
        400
      );
    }
  } else {
    toDate = defaultToDate;
  }

  const fromDateStr = fromDate.toISOString().split('T')[0];
  const toDateStr = toDate.toISOString().split('T')[0];

  // Import baseline PM schedule table
  const { baselinePmSchedule } = await import('../../lib/db/schema');

  // Query baseline PM schedule
  const baselineConditions = [
    eq(baselinePmSchedule.baselineId, baseline.id),
    gte(baselinePmSchedule.projectedDate, fromDateStr),
    lte(baselinePmSchedule.projectedDate, toDateStr),
  ];

  if (trainIdFilter.length > 0) {
    baselineConditions.push(inArray(baselinePmSchedule.trainId, trainIdFilter));
  }

  const baselinePms = await db
    .select({
      baselinePmId: baselinePmSchedule.id,
      trainId: baselinePmSchedule.trainId,
      trainNumber: trains.trainNumber,
      pmTypeId: baselinePmSchedule.pmTypeId,
      pmCode: pmTypes.pmCode,
      projectedDate: baselinePmSchedule.projectedDate,
      displayColor: pmTypes.displayColor,
    })
    .from(baselinePmSchedule)
    .innerJoin(trains, eq(baselinePmSchedule.trainId, trains.id))
    .innerJoin(pmTypes, eq(baselinePmSchedule.pmTypeId, pmTypes.id))
    .where(and(...baselineConditions))
    .orderBy(baselinePmSchedule.projectedDate);

  // Query current PM schedule for comparison
  const currentConditions = [
    gte(pmSchedule.targetDate, fromDateStr),
    lte(pmSchedule.targetDate, toDateStr),
    isNull(pmSchedule.scenarioId), // Production schedule only
  ];

  if (trainIdFilter.length > 0) {
    currentConditions.push(inArray(pmSchedule.trainId, trainIdFilter));
  }

  const currentPms = await db
    .select({
      pmId: pmSchedule.id,
      trainId: pmSchedule.trainId,
      pmTypeId: pmSchedule.pmTypeId,
      targetDate: pmSchedule.targetDate,
    })
    .from(pmSchedule)
    .where(and(...currentConditions));

  // Build a map of current PM positions by train+pmType+date (or nearest)
  const currentPmMap = new Map<string, { pmId: string; targetDate: string }>();
  for (const pm of currentPms) {
    // Key by train+pmType (we'll find the closest match)
    const key = `${pm.trainId}:${pm.pmTypeId}`;
    const existing = currentPmMap.get(key);
    if (!existing || pm.targetDate < existing.targetDate) {
      // Keep the earliest PM of this type for this train
      currentPmMap.set(key, { pmId: pm.pmId, targetDate: pm.targetDate });
    }
  }

  // Create a set of current PM IDs for "added" detection
  const currentPmKeys = new Set<string>();
  for (const pm of currentPms) {
    currentPmKeys.add(`${pm.trainId}:${pm.pmTypeId}:${pm.targetDate}`);
  }

  // Calculate drift and build response
  type BaselineStatus = 'UNCHANGED' | 'MOVED' | 'ADDED' | 'REMOVED';
  const pmBlocks: Array<{
    pmId: string;
    trainId: string;
    trainNumber: string;
    pmCode: string;
    baselineDate: string;
    currentDate: string | null;
    driftDays: number;
    status: BaselineStatus;
    displayColor: string;
  }> = [];

  // Track baseline PMs
  const baselinePmKeys = new Set<string>();

  for (const bpm of baselinePms) {
    const key = `${bpm.trainId}:${bpm.pmTypeId}`;
    const exactKey = `${bpm.trainId}:${bpm.pmTypeId}:${bpm.projectedDate}`;
    baselinePmKeys.add(exactKey);

    const currentPm = currentPmMap.get(key);
    const baselineDate = new Date(bpm.projectedDate);

    let status: BaselineStatus;
    let currentDate: string | null = null;
    let driftDays = 0;

    if (!currentPm) {
      // PM exists in baseline but not in current schedule (within date range)
      status = 'REMOVED';
    } else if (currentPm.targetDate === bpm.projectedDate) {
      status = 'UNCHANGED';
      currentDate = currentPm.targetDate;
    } else {
      status = 'MOVED';
      currentDate = currentPm.targetDate;
      const currentDateObj = new Date(currentPm.targetDate);
      driftDays = Math.round((currentDateObj.getTime() - baselineDate.getTime()) / (1000 * 60 * 60 * 24));
    }

    pmBlocks.push({
      pmId: bpm.baselinePmId,
      trainId: bpm.trainId,
      trainNumber: bpm.trainNumber,
      pmCode: bpm.pmCode,
      baselineDate: bpm.projectedDate,
      currentDate,
      driftDays,
      status,
      displayColor: bpm.displayColor ?? '#6B7280', // Gray for shadow
    });
  }

  // Find PMs that exist in current but not in baseline (ADDED)
  for (const pm of currentPms) {
    const exactKey = `${pm.trainId}:${pm.pmTypeId}:${pm.targetDate}`;
    if (!baselinePmKeys.has(exactKey)) {
      // Check if there's ANY baseline PM for this train+pmType
      const hasBaseline = baselinePms.some(b => b.trainId === pm.trainId && b.pmTypeId === pm.pmTypeId);
      if (!hasBaseline) {
        // This is a truly added PM
        const train = await db.select({ trainNumber: trains.trainNumber }).from(trains).where(eq(trains.id, pm.trainId)).limit(1);
        const pmType = await db.select({ pmCode: pmTypes.pmCode, displayColor: pmTypes.displayColor }).from(pmTypes).where(eq(pmTypes.id, pm.pmTypeId)).limit(1);

        if (train.length > 0 && pmType.length > 0) {
          pmBlocks.push({
            pmId: pm.pmId,
            trainId: pm.trainId,
            trainNumber: train[0].trainNumber,
            pmCode: pmType[0].pmCode,
            baselineDate: pm.targetDate, // Use current date as reference
            currentDate: pm.targetDate,
            driftDays: 0,
            status: 'ADDED',
            displayColor: pmType[0].displayColor ?? '#10B981', // Green for added
          });
        }
      }
    }
  }

  // Calculate summary statistics
  const summary = {
    totalPms: pmBlocks.length,
    movedPms: pmBlocks.filter(b => b.status === 'MOVED').length,
    addedPms: pmBlocks.filter(b => b.status === 'ADDED').length,
    removedPms: pmBlocks.filter(b => b.status === 'REMOVED').length,
    unchangedPms: pmBlocks.filter(b => b.status === 'UNCHANGED').length,
    avgDriftDays: pmBlocks.length > 0
      ? Math.round(pmBlocks.reduce((sum, b) => sum + Math.abs(b.driftDays), 0) / pmBlocks.length * 10) / 10
      : 0,
  };

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        baselineDate: baseline.baselineDate,
        pmBlocks,
        summary,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

